// @ts-nocheck
import React from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../../lib/api';
import { notifyError } from '../../lib/notify';
import { ExportButtons } from '../../components/ui/ExportButtons';
import * as Icons from '../../icons';

function formatTs(ts: string) {
  try {
    return new Date(ts).toLocaleString(undefined, { dateStyle: 'short', timeStyle: 'medium' });
  } catch { return ts; }
}

function formatDuration(ms: number | null | undefined) {
  if (ms == null) return '';
  if (ms < 1000) return `${ms}ms`;
  return `${(ms / 1000).toFixed(2)}s`;
}

export function HistoryPanel({
  connectionId,
  onRunQuery,
}: {
  connectionId: string;
  onRunQuery?: (sql: string) => void;
}) {
  const qc = useQueryClient();
  const [filter, setFilter] = React.useState('');
  const [db, setDb] = React.useState('');

  const { data, isFetching, refetch } = useQuery({
    queryKey: ['sql-history', connectionId, db],
    queryFn: () => api.sqlHistory(connectionId, { database: db || undefined, limit: 500 }),
    retry: false,
  });

  const clearMutation = useMutation({
    mutationFn: () => api.clearHistory(connectionId),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['sql-history', connectionId] }),
    onError: notifyError,
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => api.deleteHistoryEntry(connectionId, id),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['sql-history', connectionId] }),
    onError: notifyError,
  });

  const history: any[] = (data as any)?.history ?? [];

  const filtered = filter
    ? history.filter((h: any) => h.sql.toLowerCase().includes(filter.toLowerCase()))
    : history;

  return (
    <div className="h-full flex flex-col bg-nv-panel">
      <div className="flex items-center gap-2 px-2 py-1.5 bg-nv-toolbar border-b border-nv-border shrink-0">
        <Icons.Ke size={12} className="text-nv-query" />
        <span className="font-semibold text-xs">SQL History</span>
        <input
          value={filter}
          onChange={e => setFilter(e.target.value)}
          placeholder="Filter SQL…"
          className="nv-input text-xs flex-1 max-w-xs"
        />
        <input
          value={db}
          onChange={e => setDb(e.target.value)}
          placeholder="database"
          className="nv-input text-xs w-28"
        />
        <ExportButtons rows={filtered} filenamePrefix={`sql-history-${connectionId}`} />
        <button
          className="nv-btn"
          onClick={() => refetch()}
          disabled={isFetching}
          title="Refresh"
        >
          {isFetching
            ? <Icons.Pe size={11} className="animate-spin" />
            : <Icons.Yn size={11} />}
        </button>
        <button
          className="nv-btn text-red-500"
          onClick={() => clearMutation.mutate()}
          disabled={clearMutation.isPending}
          title="Clear history"
        >
          <Icons._Component38 size={11} />
        </button>
      </div>

      <div className="flex-1 overflow-auto">
        {filtered.length === 0 ? (
          <div className="flex items-center justify-center h-32 text-nv-textMuted text-xs">
            {history.length === 0 ? 'No SQL history yet.' : 'No results match your filter.'}
          </div>
        ) : (
          <table className="w-full text-xs">
            <thead className="sticky top-0 bg-nv-gridHeader border-b border-nv-border z-10">
              <tr>
                <th className="text-left px-2 py-1.5 font-semibold">SQL</th>
                <th className="text-left px-2 py-1.5 font-semibold w-20">DB</th>
                <th className="text-left px-2 py-1.5 font-semibold w-24">Time</th>
                <th className="text-left px-2 py-1.5 font-semibold w-16">Duration</th>
                <th className="text-left px-2 py-1.5 font-semibold w-16">Rows</th>
                <th className="w-16 px-2 py-1.5"></th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((h: any) => (
                <tr
                  key={h.id}
                  className="border-b border-nv-borderLight hover:bg-nv-hover group"
                >
                  <td className="px-2 py-1 max-w-0">
                    <div className="truncate font-mono text-2xs" title={h.sql}>{h.sql.trim()}</div>
                  </td>
                  <td className="px-2 py-1 text-nv-textMuted">{h.database ?? ''}</td>
                  <td className="px-2 py-1 text-nv-textMuted text-2xs">{formatTs(h.executedAt)}</td>
                  <td className="px-2 py-1 text-nv-textMuted">{formatDuration(h.durationMs)}</td>
                  <td className="px-2 py-1 text-nv-textMuted">{h.affectedRows ?? ''}</td>
                  <td className="px-2 py-1 flex items-center gap-1">
                    {onRunQuery && (
                      <button
                        className="nv-btn opacity-0 group-hover:opacity-100"
                        title="Open in editor"
                        onClick={() => onRunQuery(h.sql)}
                      >
                        <Icons.Ke size={10} />
                      </button>
                    )}
                    <button
                      className="nv-btn text-red-500 opacity-0 group-hover:opacity-100"
                      title="Delete"
                      onClick={() => deleteMutation.mutate(h.id)}
                    >
                      <Icons._Component2 size={10} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
