// @ts-nocheck
import { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import {
  SquareTerminal, Code2, FolderTree, Download, Columns2, Rows2,
  Copy, Search, Plus, RotateCw, Eraser, X, ChevronUp, ChevronDown, Minus,
} from 'lucide-react';
import { OsTerminalPane, type PaneApi, type PaneConnState } from './OsTerminalPane';
import { leaf, splitLeaf, removeLeaf, walkLeaves, nextLeaf, setRatio, leafCount, type PaneNode, type SplitDir } from './pane-tree';
import { useOsTerminalPrefs } from '../../store/os-terminal-prefs';
import { useWorkspaceStore, openOsTerminalTab } from '../../store/workspace';
import { SnippetsDrawer } from './SnippetsDrawer';
import { FilesDrawer } from './FilesDrawer';
import { exportPaneAsMarkdown } from './terminal-export';
import { api } from '../../lib/api';
import { T, SHADOW_SM, RADIUS, ToolButton, ToolDivider, TextInput, Badge } from './ui';
import { useIsMobile } from '../../lib/useIsMobile';

type PaneState = { state: PaneConnState; shell: string | null; err?: string; title?: string };

export function OsTerminalPanel({ tabId, active }: { tabId: string; active: boolean }) {
  const { fontSize, incFontSize, decFontSize, defaultSplitDir } = useOsTerminalPrefs();
  const isMobile = useIsMobile();
  const [tree, setTree] = useState<PaneNode>(() => leaf());
  const [activePaneId, setActivePaneId] = useState<string>(() => '');
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [paneStates, setPaneStates] = useState<Record<string, PaneState>>({});
  const [drawer, setDrawer] = useState<'none' | 'snippets' | 'files'>('none');
  const [scriptsDir, setScriptsDir] = useState<string>('');
  const [drawerWidth, setDrawerWidth] = useState<number>(400);

  const apisRef = useRef<Map<string, PaneApi>>(new Map());
  const treeRef = useRef(tree);
  treeRef.current = tree;
  const activePaneRef = useRef(activePaneId);
  activePaneRef.current = activePaneId;

  // Initialize activePaneId once the first leaf id is known.
  useEffect(() => {
    if (!activePaneId) {
      const leaves = walkLeaves(tree);
      if (leaves[0]) setActivePaneId(leaves[0].id);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [tree]);

  const activeApi = apisRef.current.get(activePaneId);

  const setPaneState = useCallback((id: string, partial: Partial<PaneState>) => {
    setPaneStates((prev) => ({ ...prev, [id]: { ...(prev[id] ?? { state: 'idle', shell: null }), ...partial } }));
  }, []);

  const handleReady = useCallback((id: string, api: PaneApi | null) => {
    if (api) apisRef.current.set(id, api);
    else apisRef.current.delete(id);
  }, []);

  const handleTitle = useCallback((id: string, title: string) => {
    setPaneState(id, { title });
    if (id === activePaneRef.current && tabId) {
      const short = title.trim();
      useWorkspaceStore.getState().updateTab(tabId, { title: short ? `Shell · ${short}` : 'Shell' });
    }
  }, [setPaneState, tabId]);

  const handleState = useCallback((id: string, state: PaneConnState, shell: string | null, err?: string) => {
    setPaneState(id, { state, shell, err });
  }, [setPaneState]);

  const handleActivateClick = useCallback((id: string) => {
    setActivePaneId(id);
  }, []);

  // ---- Pane tree ops ----
  const doSplit = useCallback((dir: SplitDir) => {
    setTree((t) => splitLeaf(t, activePaneRef.current, dir));
  }, []);

  const doClosePane = useCallback(() => {
    setTree((t) => {
      if (leafCount(t) <= 1) {
        // Close the whole tab.
        useWorkspaceStore.getState().closeTab(tabId);
        return t;
      }
      const removed = removeLeaf(t, activePaneRef.current);
      // Move active to next leaf in the resulting tree.
      const leaves = walkLeaves(removed);
      const nextId = nextLeaf(removed, activePaneRef.current) ?? leaves[0]?.id ?? '';
      if (nextId) setActivePaneId(nextId);
      return removed;
    });
  }, [tabId]);

  const cyclePane = useCallback(() => {
    const t = treeRef.current;
    const nid = nextLeaf(t, activePaneRef.current);
    if (nid) {
      setActivePaneId(nid);
      apisRef.current.get(nid)?.focus();
    }
  }, []);

  const switchTab = useCallback((dir: 1 | -1) => {
    const s = useWorkspaceStore.getState();
    const idx = s.tabs.findIndex((t) => t.id === s.activeTabId);
    if (idx === -1) return;
    const n = (idx + dir + s.tabs.length) % s.tabs.length;
    s.setActiveTab(s.tabs[n].id);
  }, []);

  // ---- Divider drag ----
  const dragRef = useRef<{ splitId: string; dir: SplitDir; rect: DOMRect } | null>(null);
  const startDrag = useCallback((splitId: string, dir: SplitDir, e: React.MouseEvent) => {
    e.preventDefault();
    const container = (e.currentTarget as HTMLElement).parentElement?.parentElement;
    if (!container) return;
    dragRef.current = { splitId, dir, rect: container.getBoundingClientRect() };
    const onMove = (ev: MouseEvent) => {
      const d = dragRef.current;
      if (!d) return;
      const ratio = d.dir === 'row'
        ? (ev.clientX - d.rect.left) / d.rect.width
        : (ev.clientY - d.rect.top) / d.rect.height;
      setTree((t) => setRatio(t, d.splitId, ratio));
    };
    const onUp = () => {
      dragRef.current = null;
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
      // refit all panes after a drag.
      apisRef.current.forEach((a) => a.fit());
    };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
  }, []);

  // ---- Drawer (terminal↔drawer) drag ----
  const startDrawerDrag = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    const container = (e.currentTarget as HTMLElement).parentElement;
    if (!container) return;
    const rect = container.getBoundingClientRect();
    const onMove = (ev: MouseEvent) => {
      const w = rect.right - ev.clientX;
      setDrawerWidth(Math.min(680, Math.max(300, w)));
    };
    const onUp = () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
      // refit terminal panes after a resize.
      apisRef.current.forEach((a) => a.fit());
    };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
  }, []);

  // ---- Search ----
  const runSearch = useCallback((forward: boolean) => {
    const api = apisRef.current.get(activePaneRef.current);
    api?.search(searchTerm, forward);
  }, [searchTerm]);

  // ---- Keyboard shortcuts (only when tab active) ----
  useEffect(() => {
    if (!active) return;
    const onKey = (e: KeyboardEvent) => {
      const ctrl = e.ctrlKey || e.metaKey;
      if (ctrl && e.shiftKey) {
        const k = e.key.toLowerCase();
        if (k === 'd') { e.preventDefault(); doSplit('row'); return; }
        if (k === 's') { e.preventDefault(); doSplit('col'); return; }
        if (k === 'w') { e.preventDefault(); doClosePane(); return; }
        if (k === 'f') { e.preventDefault(); setSearchOpen((o) => !o); return; }
        if (k === 'c') { e.preventDefault(); apisRef.current.get(activePaneRef.current)?.copy(); return; }
        if (k === 'v') { e.preventDefault(); apisRef.current.get(activePaneRef.current)?.paste(); return; }
        if (k === 't') { e.preventDefault(); openOsTerminalTab(); return; }
        if (e.key === 'ArrowRight' || e.key === 'ArrowDown') { e.preventDefault(); cyclePane(); return; }
        if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') { e.preventDefault(); cyclePane(); return; }
      }
      if (e.altKey && !e.shiftKey && (e.key === 'ArrowLeft' || e.key === 'ArrowRight')) {
        e.preventDefault();
        switchTab(e.key === 'ArrowLeft' ? -1 : 1);
        return;
      }
    };
    window.addEventListener('keydown', onKey, true);
    return () => window.removeEventListener('keydown', onKey, true);
  }, [active, doSplit, doClosePane, cyclePane, switchTab]);

  // Focus active pane + refit all when tab becomes active.
  useEffect(() => {
    if (active) {
      const t = setTimeout(() => {
        apisRef.current.forEach((a) => a.fit());
        apisRef.current.get(activePaneRef.current)?.focus();
      }, 0);
      return () => clearTimeout(t);
    }
  }, [active]);

  // Fetch scriptsDir once for the Files drawer (run-in-pane command builder).
  useEffect(() => {
    let alive = true;
    (async () => {
      try {
        const s = await api.osTerminalStatus();
        if (alive && s?.scriptsDir) setScriptsDir(s.scriptsDir);
      } catch (_) {}
    })();
    return () => { alive = false; };
  }, []);

  const runInPane = useCallback((text: string) => {
    const a = apisRef.current.get(activePaneRef.current);
    if (a) { a.focus(); a.send(text); }
  }, []);

  const exportMd = useCallback(() => {
    const a = apisRef.current.get(activePaneRef.current);
    if (!a) return;
    const st = paneStates[activePaneRef.current];
    const title = useWorkspaceStore.getState().tabs.find((t) => t.id === tabId)?.title || 'Shell';
    exportPaneAsMarkdown({ bufferText: a.bufferText, shell: st?.shell ?? null, tabTitle: title });
  }, [paneStates, tabId]);

  const leaves = useMemo(() => walkLeaves(tree), [tree]);
  const activeState = paneStates[activePaneId];
  const connState = activeState?.state ?? 'idle';
  const shellLabel = (() => {
    const s = activeState?.shell;
    if (!s) return 'Shell';
    const name = s.split('/').pop() || s;
    return /powershell|pwsh/i.test(name) ? 'PowerShell' : /bash|sh|zsh|fish/i.test(name) ? 'Bash' : name;
  })();

  const connColor = connState === 'open' ? T.success : connState === 'connecting' ? T.warning : connState === 'error' ? T.danger : T.textMuted;
  const connLabel = connState === 'open' ? 'conectado' : connState === 'connecting' ? 'conectando…' : connState === 'error' ? 'error' : connState === 'closed' ? 'cerrado' : 'idle';
  const iconSize = 14;

  const renderNode = (node: PaneNode): React.ReactNode => {
    if (node.kind === 'leaf') {
      const isActive = node.id === activePaneId;
      return (
        <div
          key={node.id}
          className="relative min-h-0 min-w-0 flex-1"
          style={{
            border: `1px solid ${isActive ? T.accent : T.borderLight}`,
            borderRadius: 6,
            overflow: 'hidden',
            background: '#0b0f17',
          }}
        >
          <OsTerminalPane
            id={node.id}
            active={active && isActive}
            fontSize={fontSize}
            onTitle={handleTitle}
            onState={handleState}
            onReady={handleReady}
            onActivateClick={handleActivateClick}
          />
          {leaves.length > 1 && (
            <button
              onClick={() => { setActivePaneId(node.id); doClosePane(); }}
              style={{
                position: 'absolute', top: 4, right: 4, zIndex: 10,
                width: 18, height: 18, display: 'flex', alignItems: 'center', justifyContent: 'center',
                color: T.textSubtle, background: 'rgba(0,0,0,0.45)', border: `1px solid ${T.borderLight}`,
                borderRadius: 4, cursor: 'pointer',
              }}
              title="Cerrar pane (Ctrl+Shift+W)"
              onMouseEnter={(e) => { e.currentTarget.style.background = T.danger; e.currentTarget.style.color = '#fff'; }}
              onMouseLeave={(e) => { e.currentTarget.style.background = 'rgba(0,0,0,0.45)'; e.currentTarget.style.color = T.textSubtle; }}
            >
              <X size={11} />
            </button>
          )}
        </div>
      );
    }
    const [a, b] = node.children;
    const horizontal = node.dir === 'row' && !isMobile;
    return (
      <div key={node.id} className="flex min-h-0 min-w-0 flex-1" style={{ flexDirection: horizontal ? 'row' : 'column' }}>
        <div style={{ flex: `${node.ratio} 1 0`, minWidth: 0, minHeight: 0, display: 'flex', padding: 2 }}>{renderNode(a)}</div>
        {!isMobile && (
        <div
          onMouseDown={(e) => startDrag(node.id, node.dir, e)}
          style={{
            width: horizontal ? 6 : 'auto',
            height: horizontal ? 'auto' : 6,
            background: T.border,
            cursor: horizontal ? 'col-resize' : 'row-resize',
            borderRadius: 3,
            margin: horizontal ? '0 1px' : '1px 0',
            transition: 'background 0.12s',
          }}
          title="Arrastrar para redimensionar"
          onMouseEnter={(e) => { e.currentTarget.style.background = T.accent; }}
          onMouseLeave={(e) => { e.currentTarget.style.background = T.border; }}
        />
        )}
        <div style={{ flex: `${1 - node.ratio} 1 0`, minWidth: 0, minHeight: 0, display: 'flex', padding: 2 }}>{renderNode(b)}</div>
      </div>
    );
  };

  return (
    <div className="h-full flex flex-col min-h-0" style={{ background: T.bg, padding: isMobile ? 4 : 8, gap: isMobile ? 4 : 8 }}>
      {/* Header card */}
      <div
        style={{
          display: 'flex', alignItems: 'center', gap: 10,
          flexWrap: isMobile ? 'wrap' : 'nowrap',
          padding: '6px 10px',
          background: T.panel,
          border: `1px solid ${T.borderLight}`,
          borderRadius: RADIUS,
          boxShadow: SHADOW_SM,
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 7 }}>
          <SquareTerminal size={16} style={{ color: T.accent }} />
          {!isMobile && <span style={{ fontSize: 13, fontWeight: 700, color: T.text }}>Terminal SO</span>}
        </div>
        <Badge color={T.accent} bg="rgba(94,176,255,0.12)" title={activeState?.shell || ''}>{shellLabel}</Badge>
        {!isMobile && (
        <span style={{ display: 'inline-flex', alignItems: 'center', gap: 5, fontSize: 11, color: T.textSubtle }}>
          <span style={{ width: 7, height: 7, borderRadius: '50%', background: connColor, boxShadow: `0 0 6px ${connColor}` }} />
          {connLabel}
          {connState === 'error' && activeState?.err ? ` · ${activeState.err}` : ''}
        </span>
        )}

        <div className="flex-1" />

        <div style={{ display: 'flex', alignItems: 'center', gap: 1, background: T.bg, border: `1px solid ${T.borderLight}`, borderRadius: 6, padding: 1 }}>
          <ToolButton icon={<Code2 size={iconSize} />} label={isMobile ? undefined : 'Snippets'} active={drawer === 'snippets'} onClick={() => setDrawer((d) => (d === 'snippets' ? 'none' : 'snippets'))} title="Biblioteca de snippets" />
          <ToolButton icon={<FolderTree size={iconSize} />} label={isMobile ? undefined : 'Archivos'} active={drawer === 'files'} onClick={() => setDrawer((d) => (d === 'files' ? 'none' : 'files'))} title="Repositorio de archivos del host" />
          <ToolDivider />
          <ToolButton icon={<Download size={iconSize} />} label={isMobile ? undefined : 'MD'} onClick={exportMd} title="Exportar pantalla del pane activo a Markdown" />
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: 1, background: T.bg, border: `1px solid ${T.borderLight}`, borderRadius: 6, padding: 1 }}>
          {!isMobile && <ToolButton icon={<Columns2 size={iconSize} />} onClick={() => doSplit('row')} title="Split vertical (Ctrl+Shift+D)" />}
          {!isMobile && <ToolButton icon={<Rows2 size={iconSize} />} onClick={() => doSplit('col')} title="Split horizontal (Ctrl+Shift+S)" />}
          {!isMobile && <ToolDivider />}
          <ToolButton icon={<Copy size={iconSize} />} onClick={() => activeApi?.copy()} title="Copiar selección (Ctrl+Shift+C)" />
          <ToolButton icon={<Search size={iconSize} />} active={searchOpen} onClick={() => setSearchOpen((o) => !o)} title="Buscar (Ctrl+Shift+F)" />
        </div>

        <div className="nv-hide-mobile" style={{ display: 'flex', alignItems: 'center', gap: 1, background: T.bg, border: `1px solid ${T.borderLight}`, borderRadius: 6, padding: 1 }}>
          <ToolButton icon={<Minus size={iconSize} />} onClick={decFontSize} title="Reducir fuente" />
          <span style={{ width: 22, textAlign: 'center', fontSize: 11, fontWeight: 600, color: T.textSubtle, fontVariantNumeric: 'tabular-nums' }}>{fontSize}</span>
          <ToolButton icon={<Plus size={iconSize} />} onClick={incFontSize} title="Aumentar fuente" />
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: 1, background: T.bg, border: `1px solid ${T.borderLight}`, borderRadius: 6, padding: 1 }}>
          <ToolButton icon={<Plus size={iconSize} />} label={isMobile ? undefined : 'Shell'} onClick={() => openOsTerminalTab()} title="Nueva shell (otra pestaña, Ctrl+Shift+T)" />
          <ToolButton icon={<RotateCw size={iconSize} />} onClick={() => activeApi?.reconnect()} title="Reconectar pane activo" />
          <ToolButton icon={<Eraser size={iconSize} />} onClick={() => activeApi?.clear()} title="Limpiar pantalla" />
        </div>
      </div>

      {/* Search bar */}
      {searchOpen && (
        <div
          style={{
            display: 'flex', alignItems: 'center', gap: 8,
            padding: '5px 10px',
            background: T.panel,
            border: `1px solid ${T.accent}`,
            borderRadius: RADIUS,
            boxShadow: SHADOW_SM,
          }}
        >
          <Search size={14} style={{ color: T.accent }} />
          <TextInput
            autoFocus
            value={searchTerm}
            onChange={(e) => { setSearchTerm(e.target.value); runSearch(true); }}
            onKeyDown={(e) => {
              if (e.key === 'Enter') { e.preventDefault(); runSearch(!e.shiftKey); }
              else if (e.key === 'Escape') { e.preventDefault(); setSearchOpen(false); setSearchTerm(''); }
            }}
            placeholder="Buscar en el scrollback…  (Enter = siguiente · Shift+Enter = anterior · Esc = cerrar)"
            style={{ flex: 1, maxWidth: 520, height: 24 }}
          />
          <ToolButton icon={<ChevronUp size={14} />} onClick={() => runSearch(false)} title="Anterior" />
          <ToolButton icon={<ChevronDown size={14} />} onClick={() => runSearch(true)} title="Siguiente" />
          <ToolButton icon={<X size={14} />} onClick={() => { setSearchOpen(false); setSearchTerm(''); }} title="Cerrar" />
        </div>
      )}

      {/* Terminal area + drawers */}
      <div className="flex-1 min-h-0 relative flex" style={{ gap: 0 }}>
        <div className="flex-1 min-h-0 relative flex flex-col" style={{ background: T.panel, border: `1px solid ${T.borderLight}`, borderRadius: RADIUS, padding: 4, boxShadow: SHADOW_SM }}>
          {renderNode(tree)}
        </div>
        {drawer !== 'none' && (
          <>
            {!isMobile && (
            <div
              onMouseDown={startDrawerDrag}
              style={{
                width: 6,
                margin: '0 1px',
                background: T.border,
                cursor: 'col-resize',
                borderRadius: 3,
                flexShrink: 0,
                alignSelf: 'stretch',
                transition: 'background 0.12s',
              }}
              title="Arrastrar para redimensionar"
              onMouseEnter={(e) => { e.currentTarget.style.background = T.accent; }}
              onMouseLeave={(e) => { e.currentTarget.style.background = T.border; }}
            />
            )}
            {drawer === 'snippets' && <SnippetsDrawer width={isMobile ? undefined : drawerWidth} onRun={runInPane} onClose={() => setDrawer('none')} />}
            {drawer === 'files' && <FilesDrawer width={isMobile ? undefined : drawerWidth} scriptsDir={scriptsDir} onRun={runInPane} onClose={() => setDrawer('none')} />}
          </>
        )}
      </div>
    </div>
  );
}
