// @ts-nocheck
import { useEffect, useRef, useState, useCallback } from 'react';
import { Terminal } from '@xterm/xterm';
import { FitAddon } from '@xterm/addon-fit';
import { WebLinksAddon } from '@xterm/addon-web-links';
import { SearchAddon } from '@xterm/addon-search';
import '@xterm/xterm/css/xterm.css';
import { api } from '../../lib/api';
import { useThemeStore } from '../../store/theme';

export type PaneConnState = 'idle' | 'connecting' | 'open' | 'closed' | 'error';

export type PaneApi = {
  term: Terminal | null;
  fit: () => void;
  focus: () => void;
  copy: () => Promise<void>;
  paste: () => Promise<void>;
  clear: () => void;
  reconnect: () => void;
  search: (term: string, forward: boolean) => boolean;
  send: (text: string) => void;
  bufferText: () => string;
};

type Props = {
  id: string;
  active: boolean;
  fontSize: number;
  onTitle?: (id: string, title: string) => void;
  onState?: (id: string, state: PaneConnState, shell: string | null, err?: string) => void;
  onReady?: (id: string, api: PaneApi | null) => void;
  onActivateClick?: (id: string) => void;
};

// OSC title parser: extracts \x1b]0;<t>\x07 / \x1b]2;<t>\x07 / \x1b]7;file://host/path\x07
const OSC_RE = /\x1b\](\d+);([^\x07\x1b]*)(?:\x07|\x1b\\)/g;
function shortPath(p: string): string {
  try {
    if (p.startsWith('file://')) {
      const u = new URL(p);
      const seg = decodeURIComponent(u.pathname);
      const base = seg.split('/').filter(Boolean).pop();
      return base ? `~/${base}` : '~';
    }
  } catch (_) {}
  return p;
}

export function OsTerminalPane({ id, active, fontSize, onTitle, onState, onReady, onActivateClick }: Props) {
  const theme = useThemeStore((s) => s.theme);
  const containerRef = useRef<HTMLDivElement | null>(null);
  const termRef = useRef<Terminal | null>(null);
  const fitRef = useRef<FitAddon | null>(null);
  const searchRef = useRef<SearchAddon | null>(null);
  const wsRef = useRef<WebSocket | null>(null);
  const oscBufRef = useRef<string>('');
  const manualCloseRef = useRef(false);
  const reconnectTimerRef = useRef<any>(null);
  const attemptsRef = useRef(0);
  const aliveRef = useRef(true);
  const shellRef = useRef<string | null>(null);
  const [connState, setConnState] = useState<PaneConnState>('idle');
  const [errorMsg, setErrorMsg] = useState<string>('');

  const emitState = useCallback((s: PaneConnState, err?: string) => {
    setConnState(s);
    setErrorMsg(err ?? '');
    onState?.(id, s, shellRef.current, err);
  }, [id, onState]);

  const emitTitle = useCallback((title: string) => {
    onTitle?.(id, title);
  }, [id, onTitle]);

  const parseOsc = useCallback((chunk: string) => {
    oscBufRef.current += chunk;
    let m: RegExpExecArray | null;
    // Run repeatedly; truncate buffer to keep only the tail after the last full match.
    OSC_RE.lastIndex = 0;
    let lastEnd = -1;
    while ((m = OSC_RE.exec(oscBufRef.current)) !== null) {
      lastEnd = OSC_RE.lastIndex;
      const code = m[1];
      const payload = m[2];
      if (code === '7') {
        emitTitle(shortPath(payload));
      } else if (code === '0' || code === '2') {
        emitTitle(payload);
      }
    }
    if (lastEnd >= 0) {
      oscBufRef.current = oscBufRef.current.slice(lastEnd);
    }
    // Cap the leftover so it can't grow unbounded (incomplete OSC tail).
    if (oscBufRef.current.length > 256) {
      const idx = oscBufRef.current.indexOf('\x1b]');
      oscBufRef.current = idx >= 0 ? oscBufRef.current.slice(idx) : '';
    }
  }, [emitTitle]);

  const connect = useCallback(async () => {
    if (!termRef.current || !aliveRef.current) return;
    manualCloseRef.current = false;
    emitState('connecting');
    try {
      const { token } = await api.osTerminalToken();
      if (!aliveRef.current) return;
      const proto = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
      const url = `${proto}//${window.location.host}/ws/os-terminal?token=${encodeURIComponent(token)}`;
      const ws = new WebSocket(url);
      wsRef.current = ws;
      ws.binaryType = 'arraybuffer';

      ws.onopen = () => {
        attemptsRef.current = 0;
        emitState('open');
        const fit = fitRef.current;
        try { fit?.fit(); } catch (_) {}
        const term = termRef.current as any;
        const cols = term?.cols ?? 80;
        const rows = term?.rows ?? 24;
        ws.send(JSON.stringify({ type: 'resize', cols, rows }));
      };
      ws.onmessage = (ev) => {
        const term = termRef.current;
        if (!term) return;
        if (typeof ev.data === 'string') {
          if (ev.data.length > 1 && ev.data.charCodeAt(0) === 0x7b /* '{' */) {
            try {
              const ctrl = JSON.parse(ev.data);
              if (ctrl.type === 'exit') {
                term.write(`\r\n\x1b[33m[proceso terminó, código ${ctrl.exitCode}]\x1b[0m\r\n`);
                return;
              }
              if (ctrl.type === 'error') {
                emitState('error', ctrl.message || 'agent error');
                return;
              }
              return; // unknown control
            } catch (_) {
              // not JSON → raw output
            }
          }
          term.write(ev.data);
          parseOsc(ev.data);
        } else if (ev.data instanceof ArrayBuffer) {
          term.write(new Uint8Array(ev.data));
        }
      };
      ws.onerror = () => {
        emitState('error', 'WebSocket error — ¿agente PTY corriendo en el host?');
      };
      ws.onclose = (ev) => {
        if (!aliveRef.current) return;
        if (ev.code === 1000 || manualCloseRef.current) {
          emitState('closed');
          return;
        }
        // Specific close codes from the agent.
        let msg = `conexión cerrada (código ${ev.code})`;
        if (ev.code === 4001) msg = 'auth: token inválido/expirado';
        else if (ev.code === 4003) msg = 'máximo de sesiones alcanzado';
        else if (ev.code === 4004) msg = 'no se pudo iniciar el shell';
        emitState('error', msg);
        // Auto-reconnect with backoff (max 5 attempts).
        if (attemptsRef.current < 5) {
          const delay = Math.min(16000, 1000 * 2 ** attemptsRef.current);
          attemptsRef.current += 1;
          reconnectTimerRef.current = setTimeout(() => { connect(); }, delay);
        }
      };
    } catch (e: any) {
      if (!aliveRef.current) return;
      emitState('error', e?.message || 'no se pudo obtener el token (¿admin?)');
      if (attemptsRef.current < 5) {
        const delay = Math.min(16000, 1000 * 2 ** attemptsRef.current);
        attemptsRef.current += 1;
        reconnectTimerRef.current = setTimeout(() => { connect(); }, delay);
      }
    }
  }, [emitState, parseOsc]);

  const disconnect = useCallback(() => {
    manualCloseRef.current = true;
    if (reconnectTimerRef.current) {
      clearTimeout(reconnectTimerRef.current);
      reconnectTimerRef.current = null;
    }
    if (wsRef.current) {
      try { wsRef.current.close(); } catch (_) {}
      wsRef.current = null;
    }
  }, []);

  // Init xterm once.
  useEffect(() => {
    if (!containerRef.current) return;
    aliveRef.current = true;
    const term = new Terminal({
      cursorBlink: true,
      fontSize,
      fontFamily: 'SF Mono, Menlo, Monaco, Consolas, "Liberation Mono", monospace',
      scrollback: 5000,
      allowProposedApi: true,
      theme: theme === 'dark' ? darkTheme : lightTheme,
    });
    const fit = new FitAddon();
    const search = new SearchAddon();
    term.loadAddon(fit);
    term.loadAddon(search);
    try { term.loadAddon(new WebLinksAddon()); } catch (_) {}
    term.open(containerRef.current);
    try { fit.fit(); } catch (_) {}
    termRef.current = term;
    fitRef.current = fit;
    searchRef.current = search;

    term.onData((data) => {
      const ws = wsRef.current;
      if (ws && ws.readyState === WebSocket.OPEN) ws.send(data);
    });
    term.onResize(({ cols, rows }) => {
      const ws = wsRef.current;
      if (ws && ws.readyState === WebSocket.OPEN) {
        ws.send(JSON.stringify({ type: 'resize', cols, rows }));
      }
    });

    // Probe status for shell label, then connect.
    (async () => {
      try {
        const s = await api.osTerminalStatus();
        shellRef.current = s?.shell ?? null;
        if (s?.available) connect();
        else emitState('error', s?.error || 'agente no disponible');
      } catch (e: any) {
        emitState('error', e?.message || 'status fetch failed');
      }
    })();

    // Expose imperative API to parent.
    onReady?.(id, {
      term,
      fit: () => { try { fit.fit(); } catch (_) {} },
      focus: () => { try { term.focus(); } catch (_) {} },
      copy: async () => {
        const sel = term.getSelection();
        if (sel) { try { await navigator.clipboard.writeText(sel); } catch (_) {} }
      },
      paste: async () => {
        try { const t = await navigator.clipboard.readText(); if (t) term.paste(t); } catch (_) {}
      },
      clear: () => { try { term.clear(); } catch (_) {} },
      reconnect: () => { disconnect(); attemptsRef.current = 0; connect(); },
      search: (q: string, forward: boolean) => {
        const sa = searchRef.current;
        if (!sa || !q) return false;
        return forward ? sa.findNext(q) : sa.findPrevious(q);
      },
      send: (text: string) => {
        try { termRef.current?.paste(text); } catch (_) {}
      },
      bufferText: () => {
        const term = termRef.current as any;
        if (!term) return '';
        const buf = term.buffer;
        const out: string[] = [];
        const n = buf?.length ?? 0;
        for (let i = 0; i < n; i++) {
          const line = buf.getLine(i);
          out.push(line ? line.translateToString(true) : '');
        }
        while (out.length && out[out.length - 1] === '') out.pop();
        return out.join('\n');
      },
    });

    return () => {
      aliveRef.current = false;
      onReady?.(id, null);
      disconnect();
      try { term.dispose(); } catch (_) {}
      termRef.current = null;
      fitRef.current = null;
      searchRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Theme changes.
  useEffect(() => {
    if (termRef.current) termRef.current.options.theme = theme === 'dark' ? darkTheme : lightTheme;
  }, [theme]);

  // Font size changes.
  useEffect(() => {
    if (termRef.current) {
      termRef.current.options.fontSize = fontSize;
      try { fitRef.current?.fit(); } catch (_) {}
    }
  }, [fontSize]);

  // Active changes: refit + focus (fixes cols=0 after hidden tab).
  useEffect(() => {
    if (active) {
      const t = setTimeout(() => {
        try { fitRef.current?.fit(); } catch (_) {}
        try { termRef.current?.focus(); } catch (_) {}
      }, 0);
      return () => clearTimeout(t);
    }
  }, [active]);

  // Resize observer → fit.
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const ro = new ResizeObserver(() => {
      if (active) { try { fitRef.current?.fit(); } catch (_) {} }
    });
    ro.observe(el);
    return () => ro.disconnect();
  }, [active]);

  return (
    <div
      className="absolute inset-0 min-h-0"
      style={{ background: 'var(--nv-bg)' }}
      onMouseDown={() => onActivateClick?.(id)}
      onContextMenu={(e) => {
        // Right-click paste.
        e.preventDefault();
        try { navigator.clipboard.readText().then((t) => { if (t) termRef.current?.paste(t); }); } catch (_) {}
      }}
    >
      <div ref={containerRef} className="absolute inset-0 p-0.5" />
      {connState === 'error' && errorMsg && (
        <div className="absolute left-1 bottom-1 px-1.5 py-0.5 text-2xs text-nv-danger bg-nv-panel/85 border border-nv-border rounded">
          {errorMsg}
        </div>
      )}
    </div>
  );
}

