// @ts-nocheck
/**
 * Lightweight non-blocking toast system.
 * Stacked in the bottom-right corner, auto-dismiss, optional action link.
 * Independent from the blocking modal notify() queue.
 */
import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, AlertTriangle, AlertCircle, Info, CheckCircle2 } from 'lucide-react';

export type ToastTone = 'danger' | 'warning' | 'info' | 'success';
export interface ToastInput {
  title: string;
  message?: string;
  icon?: React.ReactNode;
  tone?: ToastTone;
  actionLabel?: string;
  onAction?: () => void;
  duration?: number; // ms; 0 = sticky
}
interface Toast extends ToastInput { id: number; }

let pushFn: ((t: ToastInput) => void) | null = null;

export function pushToast(t: ToastInput) {
  if (pushFn) pushFn(t);
}

// Debug affordance: allows triggering a toast from devtools / QA.
// Harmless — only renders a transient notification, no data or actions exposed.
if (typeof window !== 'undefined') (window as any).nvToast = pushToast;

const TONE: Record<ToastTone, { color: string; bg: string; Icon: any }> = {
  danger:  { color: '#dc2626', bg: '#ef444418', Icon: AlertTriangle },
  warning: { color: '#d97706', bg: '#f9731618', Icon: AlertCircle },
  info:    { color: '#1976d2', bg: '#1976d218', Icon: Info },
  success: { color: '#16a34a', bg: '#16a34a18', Icon: CheckCircle2 },
};

export function ToastHost() {
  const [toasts, setToasts] = useState<Toast[]>([]);
  const idRef = useRef(0);
  const timers = useRef<Record<number, number>>({});

  const remove = useCallback((id: number) => {
    setToasts(ts => ts.filter(t => t.id !== id));
    if (timers.current[id]) { clearTimeout(timers.current[id]); delete timers.current[id]; }
  }, []);

  useEffect(() => {
    pushFn = (t) => {
      const id = ++idRef.current;
      const dur = t.duration ?? 6000;
      setToasts(ts => [...ts.slice(-3), { ...t, id }]);
      if (dur > 0) timers.current[id] = window.setTimeout(() => remove(id), dur);
    };
    return () => { pushFn = null; };
  }, [remove]);

  useEffect(() => () => {
    Object.values(timers.current).forEach(clearTimeout);
    timers.current = {};
  }, []);

  return (
    <div style={{
      position: 'fixed', right: 14, bottom: 14, zIndex: 2000,
      display: 'flex', flexDirection: 'column-reverse', gap: 8,
      pointerEvents: 'none', maxWidth: 'min(92vw, 380px)',
    }}>
      {toasts.map(t => {
        const tone = t.tone ?? 'info';
        const m = TONE[tone];
        const Icon = m.Icon;
        return (
          <div key={t.id} style={{
            pointerEvents: 'auto',
            display: 'flex', gap: 8, alignItems: 'flex-start',
            background: 'var(--nv-panel)', color: 'var(--nv-text)',
            border: `1px solid var(--nv-border)`,
            borderLeft: `3px solid ${m.color}`,
            borderRadius: 8, padding: '9px 11px',
            boxShadow: '0 6px 22px rgba(15,23,42,0.22), 0 1px 3px rgba(15,23,42,0.1)',
            animation: 'nv-toast-in 0.18s ease-out',
          }} role="alert">
            <span style={{ flexShrink: 0, marginTop: 1, color: m.color, display: 'inline-flex' }}>
              {t.icon ?? <Icon size={15} />}
            </span>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 12, fontWeight: 700, lineHeight: 1.25 }}>{t.title}</div>
              {t.message && (
                <div style={{ fontSize: 10.5, color: 'var(--nv-textSubtle)', marginTop: 2, lineHeight: 1.35, wordBreak: 'break-word' }}>{t.message}</div>
              )}
              {t.actionLabel && (
                <button type="button"
                  onClick={() => { try { t.onAction?.(); } finally { remove(t.id); } }}
                  style={{
                    marginTop: 6, fontSize: 10.5, fontWeight: 700, cursor: 'pointer',
                    background: 'none', border: 'none', padding: 0, color: 'var(--nv-accent)',
                    display: 'inline-flex', alignItems: 'center', gap: 3,
                  }}>
                  {t.actionLabel} →
                </button>
              )}
            </div>
            <button type="button" onClick={() => remove(t.id)} title="Cerrar"
              style={{ flexShrink: 0, background: 'none', border: 'none', cursor: 'pointer', padding: 0, color: 'var(--nv-textMuted)', lineHeight: 0 }}>
              <X size={13} />
            </button>
          </div>
        );
      })}
      <style>{`@keyframes nv-toast-in{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}`}</style>
    </div>
  );
}
