/* @ts-nocheck */
import React, { useState, useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Modal } from '../../components/ui/Modal';
import { api } from '../../lib/api';
import * as Icons from '../../icons';

const STRATEGIES = [
  { id: 'create', label: 'Create + Insert', desc: 'Fresh rebuild: DROP IF EXISTS + CREATE + INSERT.' },
  { id: 'truncate', label: 'Truncate + Insert', desc: 'Keep existing schema; TRUNCATE tables then reload data.' },
  { id: 'replace', label: 'Replace (merge)', desc: 'CREATE IF NOT EXISTS + REPLACE INTO. Merges, overwrites matching PKs.' },
  { id: 'ignore', label: 'Insert Ignore (merge)', desc: 'CREATE IF NOT EXISTS + INSERT IGNORE. Merges, keeps existing rows.' },
];

export function SmartRestoreModal({
  sourceConnection,
  connections,
  backupId,
  sourceDatabase,
  onClose,
  inline = false,
}: {
  sourceConnection: any;
  connections: any[];
  backupId: string;
  sourceDatabase?: string;
  onClose: () => void;
  inline?: boolean;
}) {
  const [targetId, setTargetId] = useState<string>(sourceConnection.id);
  const [database, setDatabase] = useState<string>(sourceDatabase ?? sourceConnection.defaultDb ?? '');
  const [strategy, setStrategy] = useState<string>('create');
  const [selected, setSelected] = useState<Set<string>>(() => new Set());
  const [resume, setResume] = useState(false);
  const [running, setRunning] = useState(false);
  const [done, setDone] = useState(false);
  const [logs, setLogs] = useState<string[]>([]);

  const target = connections.find((c: any) => c.id === targetId) ?? sourceConnection;

  const { data: dbList } = useQuery({
    queryKey: ['dbs', target.id],
    queryFn: () => api.databases(target.id),
    enabled: !!target.id,
  });

  const { data: manifestResp, isLoading: manifestLoading } = useQuery({
    queryKey: ['smart-manifest', backupId],
    queryFn: () => api.smartBackupManifest(backupId),
    enabled: !!backupId,
  });

  const manifest = manifestResp?.manifest;
  const completed = useMemo(() => new Set((manifestResp?.completed ?? []).map((r: any) => r)), [manifestResp]);
  const objects = manifest?.objects ?? [];

  // Initialize selection once the manifest arrives (all selected by default).
  React.useEffect(() => {
    if (objects.length && selected.size === 0) {
      setSelected(new Set(objects.map((o: any) => `${o.kind}|${o.name}`)));
    }
  }, [objects, selected.size]);

  const toggle = (key: string) => {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key); else next.add(key);
      return next;
    });
  };
  const allOn = () => setSelected(new Set(objects.map((o: any) => `${o.kind}|${o.name}`)));
  const noneOn = () => setSelected(new Set());

  const canRun = !!database && !running && objects.length > 0;

  const run = async () => {
    if (!canRun) return;
    setRunning(true);
    setDone(false);
    setLogs([]);
    const onlyObjects = objects
      .filter((o: any) => selected.has(`${o.kind}|${o.name}`))
      .map((o: any) => ({ kind: o.kind, name: o.name }));
    const body = {
      database,
      backupId,
      strategy,
      onlyObjects,
      resume,
    } as any;
    if (targetId !== sourceConnection.id) body.targetConnectionId = targetId;
    try {
      await api.smartBackupRestore(sourceConnection.id, body, (ev: any) => {
        if (ev.type === 'log') {
          setLogs((p) => [...p.slice(-80), ev.message.trim()]);
        } else if (ev.type === 'done') {
          setLogs((p) => [...p, `✓ Done (${ev.executed ?? ''} statements)`]);
          setDone(true);
        } else if (ev.type === 'error') {
          setLogs((p) => [...p, `✗ ${ev.message}`]);
        }
      });
    } catch (e: any) {
      setLogs((p) => [...p, `✗ ${e.message}`]);
    } finally {
      setRunning(false);
    }
  };

  return (
    <Modal title={`Smart Restore — ${sourceConnection.name}`} onClose={onClose} width="max-w-2xl" inline={inline}>
      <div className="space-y-3">
        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className="block text-2xs text-nv-textSubtle mb-1">Target connection</label>
            <select value={targetId} onChange={(e) => setTargetId(e.target.value)} className="nv-select w-full" disabled={running}>
              {connections.map((c: any) => <option value={c.id} key={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-2xs text-nv-textSubtle mb-1">Target database</label>
            <select value={database} onChange={(e) => setDatabase(e.target.value)} className="nv-select w-full" disabled={running}>
              <option value="">— select database —</option>
              {(dbList?.databases ?? []).map((d: any) => <option value={d} key={d}>{d}</option>)}
            </select>
          </div>
        </div>

        <div className="border border-nv-border rounded p-3 space-y-2">
          <p className="text-2xs uppercase tracking-wider text-nv-textSubtle font-semibold">Restore strategy</p>
          {STRATEGIES.map((s) => (
            <label key={s.id} className="flex items-start gap-2 text-xs">
              <input type="radio" name="strategy" checked={strategy === s.id} onChange={() => setStrategy(s.id)} disabled={running} />
              <span><span className="font-medium">{s.label}</span><span className="block text-2xs text-nv-textMuted">{s.desc}</span></span>
            </label>
          ))}
        </div>

        <div className="border border-nv-border rounded p-3 space-y-2">
          <div className="flex items-center justify-between">
            <p className="text-2xs uppercase tracking-wider text-nv-textSubtle font-semibold">Objects {manifest ? `(${objects.length})` : ''}</p>
            <div className="flex gap-1">
              <button type="button" className="nv-btn text-2xs" onClick={allOn} disabled={running || !objects.length}>All</button>
              <button type="button" className="nv-btn text-2xs" onClick={noneOn} disabled={running || !objects.length}>None</button>
            </div>
          </div>
          {manifestLoading && <p className="text-2xs text-nv-textMuted">Loading manifest…</p>}
          {!manifestLoading && objects.length === 0 && <p className="text-2xs text-nv-textMuted italic">No objects</p>}
          <div className="max-h-44 overflow-y-auto border border-nv-borderLight rounded">
            {objects.map((o: any) => {
              const key = `${o.kind}|${o.name}`;
              const isDone = completed.has(o.name) || completed.has(o.ref);
              return (
                <label key={key} className="flex items-center gap-2 px-2 py-1 text-xs hover:bg-nv-hover cursor-pointer">
                  <input type="checkbox" checked={selected.has(key)} onChange={() => toggle(key)} disabled={running} />
                  <span className="font-mono truncate flex-1">{o.kind}: {o.name}</span>
                  {o.rows != null && <span className="text-2xs text-nv-textMuted">{o.rows} rows</span>}
                  {isDone && <span className="text-2xs text-nv-success" title="Already restored (resumable)">✓</span>}
                </label>
              );
            })}
          </div>
          {completed.size > 0 && (
            <label className="flex items-center gap-2 text-xs">
              <input type="checkbox" checked={resume} onChange={(e) => setResume(e.target.checked)} disabled={running} />
              <span>Resume — skip {completed.size} object(s) already restored</span>
            </label>
          )}
        </div>

        {(running || logs.length > 0) && (
          <div className="border border-nv-border rounded">
            <div className="px-2 py-1 bg-nv-toolbar border-b border-nv-border text-2xs">Output</div>
            <pre className="p-2 max-h-44 overflow-y-auto text-2xs font-mono text-nv-textSubtle whitespace-pre-wrap">{logs.join('\n') || (running ? 'Starting…' : '')}</pre>
          </div>
        )}

        <div className="flex justify-end gap-2 pt-2">
          <button onClick={onClose} className="nv-btn">Close</button>
          <button onClick={run} disabled={!canRun} className="nv-btn-primary">
            {running ? <Icons.Pe size={11} className="animate-spin" /> : <Icons.Ku size={11} />}
            {done ? 'Done' : running ? 'Restoring...' : 'Start Restore'}
          </button>
        </div>
      </div>
    </Modal>
  );
}
