// @ts-nocheck
import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';

/** OS terminal user prefs (font size, default split direction). Persisted to localStorage. */
export const useOsTerminalPrefs = create(
  persist(
    (set) => ({
      fontSize: 13,
      defaultSplitDir: 'col',
      setFontSize: (n) => set({ fontSize: Math.min(24, Math.max(9, n)) }) ,
      incFontSize: () => set((s) => ({ fontSize: Math.min(24, s.fontSize + 1) })),
      decFontSize: () => set((s) => ({ fontSize: Math.max(9, s.fontSize - 1) })),
      setDefaultSplitDir: (d) => set({ defaultSplitDir: d === 'row' ? 'row' : 'col' }),
    }),
    {
      name: 'dbtoolbox_os_terminal_prefs',
      storage: createJSONStorage(() => localStorage),
    },
  ),
);
