// @ts-nocheck
/* Shared export helpers for tabular data (CSV + JSON blob download).
 * Extracted from TopQueriesDashboard / DpaObservabilityPanel so every
 * panel can offer consistent CSV/JSON export without duplicating logic. */

export type CsvColumn = [string, string]; // [fieldKey, headerLabel]

function triggerDownload(blob: Blob, filename: string): void {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

/** Sanitize a string for use as a filename segment. */
export function safeName(s: string, fallback = 'export'): string {
  const v = String(s ?? '')
    .replace(/[^\w.-]+/g, '_')
    .replace(/^_+|_+$/g, '');
  return v || fallback;
}

/** Convert an array of row objects to RFC4180-ish CSV text.
 *  Columns are inferred from the first row unless `columns` is provided. */
export function toCsv(rows: Record<string, any>[], columns?: CsvColumn[]): string {
  if (!rows || !rows.length) return '';
  const cols: CsvColumn[] = columns ?? Object.keys(rows[0]).map((k) => [k, k] as CsvColumn);
  const esc = (v: any) => {
    const s = v == null ? '' : String(v);
    return /[",\n\r]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s;
  };
  const lines = [cols.map((c) => esc(c[1])).join(',')];
  for (const r of rows) lines.push(cols.map((c) => esc(r[c[0]])).join(','));
  return lines.join('\n');
}

/** Download `rows` as a CSV file. */
export function exportRowsCsv(rows: Record<string, any>[], filename: string, columns?: CsvColumn[]): void {
  const csv = toCsv(rows, columns);
  triggerDownload(new Blob([csv], { type: 'text/csv;charset=utf-8' }), filename);
}

/** Download `data` (any JSON-serializable value) as a JSON file. */
export function exportRowsJson(data: any, filename: string): void {
  triggerDownload(
    new Blob([JSON.stringify(data, null, 2)], { type: 'application/json;charset=utf-8' }),
    filename,
  );
}

/** Download arbitrary text content (e.g. Markdown, SQL) as a file. */
export function exportText(text: string, filename: string, mime = 'text/plain;charset=utf-8'): void {
  triggerDownload(new Blob([String(text ?? '')], { type: mime }), filename);
}

/** Build a timestamped filename: `<prefix>-<stamp>.<ext>`. */
export function stampedName(prefix: string, ext: string, stamp = Date.now()): string {
  return `${safeName(prefix)}-${stamp}.${ext}`;
}
