// @ts-nocheck
/** Alert rules editor — thresholds, severity gates, Slack toggles. */
import React, { useState } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { Bell, Save } from 'lucide-react';
import { api } from '../../lib/api';
import { notify } from '../../lib/notify';
import { CACHE_FIRST_QUERY } from '../../lib/cacheFirstQuery';

const PARAM_LABELS: Record<string, string> = {
  ageSecCritical: 'Critical if blocking ≥ (sec)',
  ratioCritical: 'Critical if regression ratio ≥',
  totalSecCritical: 'Critical if DB time ≥ (sec/h)',
  scoreCritical: 'Critical if health score <',
};

const CATEGORY_LABELS: Record<string, string> = {
  active_blocking: 'Active Blocking',
  deadlock: 'Deadlock',
  regression: 'Regression',
  plan_instability: 'Plan Instability',
  high_cpu_query: 'High DB Time',
  index_advisor: 'Index Advisor',
  table_advisor: 'Table Advisor',
  health_score: 'Health Score',
  disk_pressure: 'Disk Pressure',
  high_memory: 'High Memory',
  stale_collector: 'Stale Collector',
  lock_contention: 'Lock Contention',
  ghost_query: 'Ghost Query',
  rapid_growth: 'Rapid Growth',
  failed_job: 'Failed Job',
};

function paramKeys(params: Record<string, unknown> | null | undefined): string[] {
  if (!params || typeof params !== 'object') return [];
  return Object.keys(params).filter(k => PARAM_LABELS[k]);
}

const LIMIT_LABELS: Record<string, string> = {
  totalSecWarning: 'Warn DB time (sec/h)',
  ratioWarning: 'Warn regression ratio',
  changesWarning: 'Warn plan changes',
  changesCritical: 'Critical plan changes',
  indexRatioWarning: 'Warn index ratio',
  ratioCritical: 'Critical index ratio',
  sizeGbWarning: 'Warn table (GB)',
  sizeGbCritical: 'Critical table (GB)',
  scoreWarning: 'Warn score below',
  pctWarning: 'Warn %',
  pctCritical: 'Critical %',
  lockPctWarning: 'Warn lock %',
  lockPctCritical: 'Critical lock %',
  minCalls: 'Min calls',
  callsCritical: 'Critical calls',
  growthPctWarning: 'Warn growth %',
  growthPctCritical: 'Critical growth %',
};

function limitKeys(limits: Record<string, unknown> | null | undefined): string[] {
  if (!limits || typeof limits !== 'object') return [];
  return Object.keys(limits);
}

export function AlertRulesPanel({ open, full }: { open: boolean; full?: boolean }) {
  const qc = useQueryClient();
  const [busyId, setBusyId] = useState<string | null>(null);
  const [drafts, setDrafts] = useState<Record<string, Record<string, unknown>>>({});

  const q = useQuery({
    queryKey: ['dpa-alert-rules'],
    queryFn: () => api.dpaAlertRules(),
    staleTime: 120_000,
    enabled: open,
    ...CACHE_FIRST_QUERY,
  });

  const rules: any[] = (q.data?.rules ?? []).filter((r: any) => full ? !r.connectionId : true);

  const getDraft = (rule: any) => drafts[rule.id] ?? rule;

  const patchRule = async (rule: any, patch: Record<string, unknown>) => {
    setBusyId(rule.id);
    try {
      await api.dpaUpdateAlertRule({ id: rule.id, ...patch });
      qc.invalidateQueries({ queryKey: ['dpa-alert-rules'] });
      qc.invalidateQueries({ queryKey: ['dpa-critical-summary'] });
      setDrafts(prev => {
        const next = { ...prev };
        delete next[rule.id];
        return next;
      });
      notify('Rule updated');
    } catch (e) {
      notify(String(e?.message ?? e));
    } finally {
      setBusyId(null);
    }
  };

  const updateDraft = (rule: any, field: string, value: unknown) => {
    setDrafts(prev => ({
      ...prev,
      [rule.id]: { ...getDraft(rule), [field]: value },
    }));
  };

  const updateParam = (rule: any, key: string, value: number) => {
    const d = getDraft(rule);
    const params = { ...(d.params ?? {}), [key]: value };
    setDrafts(prev => ({ ...prev, [rule.id]: { ...d, params } }));
  };

  const updateLimit = (rule: any, key: string, value: number) => {
    const d = getDraft(rule);
    const limits = { ...(d.limits ?? {}), [key]: value };
    setDrafts(prev => ({ ...prev, [rule.id]: { ...d, limits } }));
  };

  if (!open) return null;

  const wrapStyle = full ? {} : { marginTop: 8, padding: '8px 0 0', borderTop: '1px dashed var(--nv-border)' };

  return (
    <div style={wrapStyle}>
      {!full && (
        <div style={{ fontSize: 9, color: 'var(--nv-textSubtle)', marginBottom: 6 }}>
          Configure thresholds and Slack notifications per alert category.
        </div>
      )}
      {q.isLoading ? (
        <div style={{ fontSize: 10, color: 'var(--nv-textMuted)' }}>Loading rules…</div>
      ) : rules.length === 0 ? (
        <div style={{ fontSize: 10, color: 'var(--nv-textMuted)' }}>No rules configured</div>
      ) : (
        rules.map(rule => {
          const d = getDraft(rule);
          const pKeys = paramKeys(d.params);
          const lKeys = limitKeys(d.limits);
          const dirty = !!drafts[rule.id];
          return (
            <div key={rule.id} style={{
              marginBottom: 6, padding: '6px 8px', borderRadius: 6,
              background: 'var(--nv-surface)', border: '1px solid var(--nv-border)',
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 4 }}>
                <label style={{ display: 'flex', alignItems: 'center', gap: 4, cursor: 'pointer', flex: 1, minWidth: 0 }}>
                  <input
                    type="checkbox"
                    checked={!!d.enabled}
                    onChange={e => patchRule(rule, { enabled: e.target.checked })}
                    disabled={busyId === rule.id}
                  />
                  <span style={{ fontSize: 10, fontWeight: 600, color: 'var(--nv-text)' }}>
                    {CATEGORY_LABELS[d.category] ?? d.name ?? d.category}
                  </span>
                </label>
                <label style={{ display: 'flex', alignItems: 'center', gap: 3, fontSize: 9, color: 'var(--nv-textMuted)', cursor: 'pointer' }}>
                  <Bell size={10} />
                  <input
                    type="checkbox"
                    checked={!!d.notifySlack}
                    onChange={e => patchRule(rule, { notifySlack: e.target.checked })}
                    disabled={busyId === rule.id || !d.enabled}
                  />
                  Slack
                </label>
                <label style={{ display: 'flex', alignItems: 'center', gap: 3, fontSize: 9, color: 'var(--nv-textMuted)', cursor: 'pointer' }}>
                  <input
                    type="checkbox"
                    checked={!!d.notifyEmail}
                    onChange={e => patchRule(rule, { notifyEmail: e.target.checked })}
                    disabled={busyId === rule.id || !d.enabled}
                  />
                  Email
                </label>
                <label style={{ display: 'flex', alignItems: 'center', gap: 3, fontSize: 9, color: 'var(--nv-textMuted)', cursor: 'pointer' }}>
                  <input
                    type="checkbox"
                    checked={!!d.notifyWebhook}
                    onChange={e => patchRule(rule, { notifyWebhook: e.target.checked })}
                    disabled={busyId === rule.id || !d.enabled}
                  />
                  Webhook
                </label>
              </div>
              <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', alignItems: 'center' }}>
                <label style={{ fontSize: 9, color: 'var(--nv-textMuted)' }}>
                  Min severity{' '}
                  <select
                    value={d.minSeverity ?? 'warning'}
                    onChange={e => updateDraft(rule, 'minSeverity', e.target.value)}
                    disabled={busyId === rule.id || !d.enabled}
                    style={{
                      fontSize: 9, padding: '2px 4px', borderRadius: 4,
                      background: 'var(--nv-toolbar)', border: '1px solid var(--nv-border)', color: 'var(--nv-text)',
                    }}
                  >
                    <option value="warning">warning+</option>
                    <option value="critical">critical only</option>
                  </select>
                </label>
                {pKeys.map(k => (
                  <label key={k} style={{ fontSize: 9, color: 'var(--nv-textMuted)' }}>
                    {PARAM_LABELS[k]}{' '}
                    <input
                      type="number"
                      value={d.params?.[k] ?? ''}
                      onChange={e => updateParam(rule, k, Number(e.target.value))}
                      disabled={busyId === rule.id || !d.enabled}
                      style={{
                        width: 52, fontSize: 9, padding: '2px 4px', borderRadius: 4,
                        background: 'var(--nv-toolbar)', border: '1px solid var(--nv-border)', color: 'var(--nv-text)',
                      }}
                    />
                  </label>
                ))}
                {lKeys.map(k => (
                  <label key={`l-${k}`} style={{ fontSize: 9, color: 'var(--nv-textMuted)' }}>
                    {(LIMIT_LABELS[k] ?? k)}{' '}
                    <input type="number" value={d.limits?.[k] ?? ''}
                      onChange={e => updateLimit(rule, k, Number(e.target.value))}
                      disabled={busyId === rule.id || !d.enabled}
                      style={{ width: 52, fontSize: 9, padding: '2px 4px', borderRadius: 4, background: 'var(--nv-toolbar)', border: '1px solid var(--nv-border)', color: 'var(--nv-text)' }} />
                  </label>
                ))}
                {dirty && (
                  <button
                    type="button"
                    disabled={busyId === rule.id}
                    onClick={() => patchRule(rule, {
                      minSeverity: d.minSeverity,
                      params: d.params,
                      limits: d.limits,
                      windowHours: d.windowHours,
                    })}
                    style={{
                      display: 'flex', alignItems: 'center', gap: 3,
                      padding: '2px 7px', borderRadius: 4, fontSize: 9, fontWeight: 600,
                      cursor: busyId === rule.id ? 'wait' : 'pointer',
                      background: '#0ea5e918', border: '1px solid #0ea5e950', color: '#38bdf8',
                    }}
                  >
                    <Save size={9} />
                    Save
                  </button>
                )}
              </div>
            </div>
          );
        })
      )}
    </div>
  );
}
