// @ts-nocheck
import { useState, useRef, useEffect } from 'react';
import { Download } from 'lucide-react';
import { exportRowsCsv, exportRowsJson, safeName, stampedName } from '../../lib/export';
import { notify } from '../../lib/notify';

type Variant = 'inline' | 'menu';

interface Props {
  rows: Record<string, any>[] | null | undefined;
  filenamePrefix?: string;
  columns?: [string, string][];
  /** Override the JSON payload; defaults to { exportedAt, count, rows }. */
  jsonPayload?: any;
  variant?: Variant;
  label?: string;
  disabled?: boolean;
}

export function ExportButtons({
  rows,
  filenamePrefix = 'export',
  columns,
  jsonPayload,
  variant = 'inline',
  label = 'Export',
  disabled = false,
}: Props) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!open) return;
    const onDoc = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    };
    document.addEventListener('mousedown', onDoc);
    return () => document.removeEventListener('mousedown', onDoc);
  }, [open]);

  const hasRows = Array.isArray(rows) && rows.length > 0;
  if (disabled || !hasRows) return null;

  const onCsv = () => {
    exportRowsCsv(rows as Record<string, any>[], stampedName(filenamePrefix, 'csv'), columns);
    notify('Exportado a CSV');
    setOpen(false);
  };
  const onJson = () => {
    const data =
      jsonPayload ??
      { exportedAt: new Date().toISOString(), count: (rows as any[]).length, rows };
    exportRowsJson(data, stampedName(filenamePrefix, 'json'));
    notify('Exportado a JSON');
    setOpen(false);
  };

  if (variant === 'menu') {
    return (
      <div className="relative" ref={ref}>
        <button
          type="button"
          className="nv-btn !py-0.5 !text-2xs"
          onClick={() => setOpen((v) => !v)}
          title="Exportar"
        >
          <Download size={10} /> {label}
        </button>
        {open && (
          <div className="absolute right-0 top-full mt-1 z-30 bg-nv-panel border border-nv-border rounded shadow-xl text-2xs min-w-[88px]">
            <button
              type="button"
              className="block w-full text-left px-3 py-1.5 hover:bg-nv-hover"
              onClick={onCsv}
            >
              CSV
            </button>
            <button
              type="button"
              className="block w-full text-left px-3 py-1.5 hover:bg-nv-hover"
              onClick={onJson}
            >
              JSON
            </button>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="flex items-center gap-1">
      <button
        type="button"
        className="nv-btn !py-0.5 !text-2xs"
        onClick={onCsv}
        title="Exportar a CSV"
      >
        CSV
      </button>
      <button
        type="button"
        className="nv-btn !py-0.5 !text-2xs"
        onClick={onJson}
        title="Exportar a JSON"
      >
        JSON
      </button>
    </div>
  );
}
