export function QueryStoreSection({ connections }: { connections: any[] }) {
  const qc = useQueryClient();
  const [connId, setConnId] = useState('');
  const q = useQuery({
    queryKey: ['settings-qs', connId],
    queryFn: () => api.settingsQueryStore(connId || undefined),
    enabled: true,
  });
  const [fleet, setFleet] = useState<any>({});
  const [connCfg, setConnCfg] = useState<any>({});
  const [inheritsFleet, setInheritsFleet] = useState(true);
  useEffect(() => {
    if (q.data?.fleet) setFleet(q.data.fleet);
    if (connId && q.data?.connection) {
      setConnCfg(q.data.connection);
      setInheritsFleet(q.data.connection.inheritsFleetDefaults !== false);
    } else {
      setConnCfg({});
      setInheritsFleet(true);
    }
  }, [q.data, connId]);
  const fleetFields = ['intervalMinutes', 'retentionDays', 'topNPlans', 'regressionMultiplier', 'plansPerSnapshot', 'sampleSqlPerQuery'];
  const saveFleet = async () => {
    await api.settingsPutQueryStore({ fleet });
    notify('Fleet defaults saved');
    qc.invalidateQueries({ queryKey: ['settings-qs'] });
  };
  const saveConn = async () => {
    if (!connId) return;
    await api.settingsPutQueryStore({
      connectionId: connId,
      connection: { ...connCfg, inheritsFleetDefaults: inheritsFleet },
    });
    notify('Connection override saved');
    qc.invalidateQueries({ queryKey: ['settings-qs', connId] });
  };
  return (
    <div>
      <div style={sectionTitle}>Query Store fleet defaults</div>
      <div style={sectionDesc}>New connections inherit these values unless overridden.</div>
      {fleetFields.map(k => (
        <NumField key={k} label={k} value={fleet[k] ?? 0} step={k === 'regressionMultiplier' ? 0.1 : 1}
          onChange={v => setFleet({ ...fleet, [k]: v })} />
      ))}
      <SaveBar onSave={saveFleet} dirty />
      <select value={connId} onChange={e => setConnId(e.target.value)} style={{ ...fieldStyle, marginTop: 16 }}>
        <option value="">Connection override…</option>
        {connections.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
      </select>
      {connId && (
        <div style={{ marginTop: 12, padding: 12, border: '1px solid var(--nv-border)', borderRadius: 8 }}>
          <div style={sectionTitle}>Override: {connections.find(c => c.id === connId)?.name ?? connId}</div>
          <label style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 10, fontSize: 12 }}>
            <input type="checkbox" checked={inheritsFleet} onChange={e => setInheritsFleet(e.target.checked)} />
            Inherit fleet defaults
          </label>
          {!inheritsFleet && fleetFields.map(k => (
            <NumField key={`c-${k}`} label={k} value={connCfg[k] ?? fleet[k] ?? 0}
              step={k === 'regressionMultiplier' ? 0.1 : 1}
              onChange={v => setConnCfg({ ...connCfg, [k]: v })} />
          ))}
          <SaveBar onSave={saveConn} dirty />
          {q.data?.effective && (
            <div style={{ marginTop: 8 }}>
              <div style={{ fontSize: 11, fontWeight: 600, marginBottom: 4 }}>Effective config</div>
              <pre style={{ fontSize: 10, margin: 0, overflow: 'auto' }}>{JSON.stringify(q.data.effective, null, 2)}</pre>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

