export function UsersSection() {
  const qc = useQueryClient();
  const q = useQuery({ queryKey: ['settings-users'], queryFn: () => api.settingsUsers() });
  const me = useQuery({ queryKey: ['me'], queryFn: () => api.me() });
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [role, setRole] = useState('viewer');
  const [busy, setBusy] = useState(false);
  const [roleDraft, setRoleDraft] = useState<Record<string, string>>({});

  const myId = me.data?.user?.id;
  const refresh = () => qc.invalidateQueries({ queryKey: ['settings-users'] });

  const create = async () => {
    if (!email.trim() || password.length < 8) {
      notify('Email and password (min 8 chars) required');
      return;
    }
    setBusy(true);
    try {
      await api.settingsCreateUser(email.trim(), password, role);
      notify('User created');
      setEmail(''); setPassword(''); setRole('viewer');
      refresh();
    } catch (e) { notify(String(e?.message ?? e)); } finally { setBusy(false); }
  };

  const saveRole = async (u: any) => {
    const next = roleDraft[u.id] ?? u.role;
    if (next === u.role) return;
    try {
      await api.settingsUpdateUserRole(u.id, next);
      notify('Role updated');
      setRoleDraft(d => { const c = { ...d }; delete c[u.id]; return c; });
      refresh();
    } catch (e) { notify(String(e?.message ?? e)); }
  };

  const resetPassword = async (u: any) => {
    const pw = window.prompt(`New password for ${u.email} (min 8 characters)`) ?? '';
    if (pw.trim() === '') return;
    if (pw.length < 8) { notify('Password must be at least 8 characters'); return; }
    try {
      await api.settingsChangeUserPassword(u.id, pw);
      notify('Password reset');
    } catch (e) { notify(String(e?.message ?? e)); }
  };

  const remove = async (u: any) => {
    if (u.id === myId) { notify('Cannot delete yourself'); return; }
    if (!window.confirm(`Delete user ${u.email}?`)) return;
    try {
      await api.settingsDeleteUser(u.id);
      notify('User deleted');
      refresh();
    } catch (e) { notify(String(e?.message ?? e)); }
  };

  const ROLES = ['viewer', 'editor', 'dba', 'admin'];
  const rowStyle: React.CSSProperties = { display: 'flex', alignItems: 'center', gap: 8, marginTop: 6, fontSize: 12 };
  const btn: React.CSSProperties = { padding: '3px 8px', borderRadius: 5, border: '1px solid var(--nv-border)', background: 'transparent', color: 'var(--nv-text)', cursor: 'pointer', fontSize: 11 };
  const btnDanger: React.CSSProperties = { ...btn, color: '#f87171' };

  return (
    <div>
      <div style={sectionTitle}>App users</div>
      <div style={sectionDesc}>Create, change roles, reset passwords, or remove application users.</div>

      {(q.data?.users ?? []).map((u: any) => {
        const draft = roleDraft[u.id] ?? u.role;
        const dirty = draft !== u.role;
        const isSelf = u.id === myId;
        return (
          <div key={u.id} style={rowStyle}>
            <span style={{ minWidth: 200, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
              {u.email}{isSelf ? ' (you)' : ''}
            </span>
            <select value={draft} onChange={e => setRoleDraft(d => ({ ...d, [u.id]: e.target.value }))} style={{ ...fieldStyle, padding: '2px 6px', width: 90 }}>
              {ROLES.map(r => <option key={r} value={r}>{r}</option>)}
            </select>
            <button type="button" onClick={() => saveRole(u)} disabled={!dirty} style={{ ...btn, opacity: dirty ? 1 : 0.4, cursor: dirty ? 'pointer' : 'default' }}>Save role</button>
            <button type="button" onClick={() => resetPassword(u)} style={btn}>Reset password</button>
            <button type="button" onClick={() => remove(u)} disabled={isSelf} style={{ ...btnDanger, opacity: isSelf ? 0.4 : 1, cursor: isSelf ? 'default' : 'pointer' }}>Delete</button>
          </div>
        );
      })}

      <div style={{ ...sectionTitle, marginTop: 18, fontSize: 13 }}>New user</div>
      <input placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} style={{ ...fieldStyle, marginTop: 8 }} />
      <input placeholder="Password (min 8 chars)" type="password" value={password} onChange={e => setPassword(e.target.value)} style={{ ...fieldStyle, marginTop: 8 }} />
      <select value={role} onChange={e => setRole(e.target.value)} style={{ ...fieldStyle, marginTop: 8 }}>
        {ROLES.map(r => <option key={r} value={r}>{r}</option>)}
      </select>
      <button type="button" onClick={create} disabled={busy || !email.trim() || password.length < 8}
        style={{ marginTop: 8, padding: '6px 12px', borderRadius: 6, background: 'var(--nv-accent)', color: '#fff', border: 'none', cursor: 'pointer', opacity: (busy || !email.trim() || password.length < 8) ? 0.5 : 1 }}>
        {busy ? 'Creating…' : 'Create'}
      </button>
    </div>
  );
}

export function InfraSection() {
  const q = useQuery({ queryKey: ['settings-infra'], queryFn: () => api.settingsInfra() });
  return (<div><div style={sectionTitle}>Infrastructure</div><pre style={{ fontSize: 10 }}>{JSON.stringify(q.data ?? {}, null, 2)}</pre></div>);
}

export function VpnSection() {
  const qc = useQueryClient();
  const [busy, setBusy] = useState<'up' | 'down' | null>(null);
  const st = useQuery({ queryKey: ['vpn-status'], queryFn: () => api.vpnStatus(), refetchInterval: 5000 });
  const log = useQuery({ queryKey: ['vpn-log'], queryFn: () => api.vpnLog(300), refetchInterval: 8000 });
  const s = st.data ?? {};

  const act = async (kind: 'up' | 'down') => {
    setBusy(kind);
    try {
      const r: any = await (kind === 'up' ? api.vpnUp() : api.vpnDown());
      notify(r?.active ? `VPN ${kind === 'up' ? 'connected' : 'down'}` : 'VPN down');
      qc.invalidateQueries({ queryKey: ['vpn-status'] });
      qc.invalidateQueries({ queryKey: ['vpn-log'] });
    } catch (e) { notify(String((e as any)?.message ?? e)); } finally { setBusy(null); }
  };

  return (
    <div>
      <div style={sectionTitle}>VPN</div>
      <div style={sectionDesc}>OpenVPN tunnel control for connections flagged use_vpn. Status refreshes automatically.</div>

      <div style={{ display: 'flex', gap: 18, margin: '12px 0', fontSize: 12, flexWrap: 'wrap' }}>
        <span>Enabled: <b>{s.enabled ? 'yes' : 'no'}</b></span>
        <span>Tunnel: <b style={{ color: s.active ? 'green' : '#b91c1c' }}>{s.active ? 'UP' : 'DOWN'}</b></span>
        <span>Started by this app: <b>{s.weStarted ? 'yes' : 'no'}</b></span>
      </div>

      <div style={{ display: 'flex', gap: 8, marginBottom: 16 }}>
        <button type="button" onClick={() => act('up')} disabled={busy !== null || s.active} style={{ padding: '6px 14px', fontSize: 12, borderRadius: 6, border: '1px solid var(--nv-border)', cursor: 'pointer', opacity: busy || s.active ? 0.5 : 1 }}>{busy === 'up' ? 'Connecting…' : 'Connect'}</button>
        <button type="button" onClick={() => act('down')} disabled={busy !== null || !s.active} style={{ padding: '6px 14px', fontSize: 12, borderRadius: 6, border: '1px solid var(--nv-border)', cursor: 'pointer', opacity: busy || !s.active ? 0.5 : 1 }}>{busy === 'down' ? 'Disconnecting…' : 'Disconnect'}</button>
        <button type="button" onClick={() => { qc.invalidateQueries({ queryKey: ['vpn-log'] }); qc.invalidateQueries({ queryKey: ['vpn-status'] }); }} style={{ padding: '6px 14px', fontSize: 12, borderRadius: 6, border: '1px solid var(--nv-border)', cursor: 'pointer' }}>Refresh</button>
      </div>

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
        <span style={{ fontSize: 12, fontWeight: 600 }}>OpenVPN log</span>
        <span style={{ fontSize: 10, color: 'var(--nv-textMuted)' }}>{log.data?.path ?? ''}</span>
      </div>
      <pre style={{ background: 'var(--nv-surface)', border: '1px solid var(--nv-border)', borderRadius: 6, padding: 8, fontSize: 10, maxHeight: 320, overflow: 'auto', whiteSpace: 'pre-wrap' }}>{log.data?.available ? (log.data.lines || '(empty log)') : (log.isLoading ? 'loading…' : 'log not available')}</pre>
    </div>
  );
}

export function AiSection() {
  const qc = useQueryClient();
  const q = useQuery({ queryKey: ['settings-ai-openai'], queryFn: () => api.settingsAiOpenAi() });
  const [enabled, setEnabled] = useState(false);
  const [baseUrl, setBaseUrl] = useState('https://api.openai.com/v1');
  const [model, setModel] = useState('gpt-4o-mini');
  const [organization, setOrganization] = useState('');
  const [apiKey, setApiKey] = useState('');
  const [busy, setBusy] = useState(false);
  const [testing, setTesting] = useState(false);

  useEffect(() => {
    if (q.data) {
      setEnabled(!!q.data.enabled);
      setBaseUrl(q.data.baseUrl ?? 'https://api.openai.com/v1');
      setModel(q.data.model ?? 'gpt-4o-mini');
      setOrganization(q.data.organization ?? '');
    }
  }, [q.data]);

  const d = q.data ?? {};
  const save = async () => {
    setBusy(true);
    try {
      const patch: any = { enabled, baseUrl, model, organization };
      if (apiKey) patch.apiKey = apiKey;
      await api.settingsPutAiOpenAi(patch);
      notify('Saved'); setApiKey('');
      qc.invalidateQueries({ queryKey: ['settings-ai-openai'] });
    } catch (e) { notify(String(e?.message ?? e)); } finally { setBusy(false); }
  };

  const test = async () => {
    setTesting(true);
    try {
      const r: any = await api.settingsTestAiOpenAi();
      notify(r?.ok ? `OK — ${r.message ?? 'reachable'}${r.model ? ' (' + r.model + ')' : ''}` : `Failed — ${r?.message ?? 'unknown'}`);
    } catch (e) { notify(String(e?.message ?? e)); } finally { setTesting(false); }
  };

  return (
    <div>
      <div style={sectionTitle}>AI Provider (OpenAI)</div>
      <div style={sectionDesc}>Connection layer for upcoming AI features (SQL explain, alert triage). API key is encrypted at rest.</div>
      <div style={{ fontSize: 12, margin: '8px 0' }}>Status: {d.configured ? 'API key set' : 'no API key'} · {d.enabled ? 'enabled' : 'disabled'}</div>

      <label style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 10 }}>
        <input type="checkbox" checked={enabled} onChange={e => setEnabled(e.target.checked)} />
        <span style={{ fontSize: 12 }}>Enabled</span>
      </label>
      <label style={{ display: 'block', marginBottom: 10 }}><span style={labelStyle}>Base URL</span>
        <input value={baseUrl} onChange={e => setBaseUrl(e.target.value)} style={fieldStyle} /></label>
      <label style={{ display: 'block', marginBottom: 10 }}><span style={labelStyle}>Model</span>
        <input value={model} onChange={e => setModel(e.target.value)} style={fieldStyle} placeholder="gpt-4o-mini" /></label>
      <label style={{ display: 'block', marginBottom: 10 }}><span style={labelStyle}>Organization (optional)</span>
        <input value={organization} onChange={e => setOrganization(e.target.value)} style={fieldStyle} /></label>
      <label style={{ display: 'block', marginBottom: 10 }}><span style={labelStyle}>API key {d.hasApiKey ? '(set — leave blank to keep)' : ''}</span>
        <input value={apiKey} onChange={e => setApiKey(e.target.value)} style={fieldStyle} type="password" placeholder={d.hasApiKey ? '••••••••' : 'sk-...'} /></label>

      <div style={{ display: 'flex', gap: 8 }}>
        <SaveBar onSave={save} busy={busy} dirty />
        <button type="button" onClick={test} disabled={testing} style={{ marginTop: 16, padding: '6px 12px', fontSize: 12, borderRadius: 6, border: '1px solid var(--nv-border)', cursor: 'pointer', opacity: testing ? 0.5 : 1 }}>{testing ? 'Testing…' : 'Test connection'}</button>
      </div>
    </div>
  );
}
