/* AppHeader — redesigned toolbar with grouped dropdown menus */
// @ts-nocheck

import React, { useState, useEffect, useRef } from 'react';
import { useQuery, useQueryClient, useMutation } from '@tanstack/react-query';
import {
  Home, Plus, UserCircle, Archive, Eye, Database,
  ServerCrash, PlugZap, Unplug, RefreshCw, LogOut,
  Sun, Moon, ChevronDown, Menu,
  Link2, Code2,
  RotateCcw, Clock, CalendarClock,
  Activity, Info, ShieldCheck, UploadCloud,
  ArrowLeftRight, GitCompare, Network, Settings2,
  TerminalSquare,
} from 'lucide-react';
import { api } from '../../lib/api';
import { appConfig, isLiteEdition } from '../../lib/config';
import { useSettingsModalStore } from '../../store/settings-modal';
import { notifyError } from '../../lib/notify';
import { useThemeStore } from '../../store/theme';
import { useWorkspaceStore } from '../../store/workspace';
import { useIsMobile } from '../../lib/useIsMobile';
import { SchedulerStatusBadge } from './SchedulerStatusBadge';
import { NotificationStatusBadge } from './NotificationStatusBadge';
import { ServiceStatusGroup } from './StatusIconButton';

// ─── VPN Badge ──────────────────────────────────────────────────────────────
function VpnBadge({ connection: conn }) {
  const qc = useQueryClient();
  const { data } = useQuery({
    queryKey: ['vpn-status', conn?.id],
    queryFn: () => conn ? api.vpnStatusForConnection(conn.id) : api.vpnStatus(),
    refetchInterval: 15000,
    retry: false,
    enabled: !!conn,
  });
  const up = useMutation({
    mutationFn: () => conn ? api.vpnUpForConnection(conn.id) : api.vpnUp(),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['vpn-status', conn?.id] }),
    onError: (e) => notifyError(e),
  });
  const down = useMutation({
    mutationFn: () => conn ? api.vpnDownForConnection(conn.id) : api.vpnDown(),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['vpn-status', conn?.id] }),
  });

  if (!conn?.useVpn || !data) return null;
  const active = data.active;

  return (
    <div className="flex items-center gap-2 text-xs">
      <div className={`flex items-center gap-1.5 px-2 py-1 rounded text-xs font-medium ${
        active ? 'bg-green-900/40 text-green-300 border border-green-800/50' : 'bg-amber-900/40 text-amber-300 border border-amber-800/50'
      }`}>
        {active ? <PlugZap size={11} /> : <Unplug size={11} />}
        <span>{conn.name} VPN {active ? 'Connected' : 'Disconnected'}</span>
      </div>
      {active
        ? <button onClick={() => down.mutate()} disabled={down.isPending} className="nv-btn !py-1">Disconnect</button>
        : <button onClick={() => up.mutate()} disabled={up.isPending} className="nv-btn !py-1">
            {up.isPending ? <RefreshCw size={10} className="animate-spin" /> : 'Connect'}
          </button>
      }
    </div>
  );
}

// ─── Dropdown Menu ───────────────────────────────────────────────────────────
interface MenuItem {
  icon: React.ReactNode;
  label: string;
  onClick: () => void;
  disabled?: boolean;
  separator?: boolean;
}

function DropdownMenu({ items, children, align = 'left' }: {
  items: MenuItem[];
  children: React.ReactNode;
  align?: 'left' | 'right';
}) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!open) return;
    const handler = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [open]);

  return (
    <div ref={ref} style={{ position: 'relative', display: 'inline-block' }}>
      <div onClick={() => setOpen((o) => !o)}>
        {children}
      </div>
      {open && (
        <div style={{
          position: 'absolute',
          top: '100%',
          [align === 'right' ? 'right' : 'left']: 0,
          zIndex: 1000,
          minWidth: 200,
          background: 'var(--nv-panel)',
          border: '1px solid var(--nv-border)',
          borderRadius: 6,
          boxShadow: '0 8px 24px rgba(0,0,0,0.4)',
          padding: '4px 0',
          marginTop: 2,
        }}>
          {items.map((item, i) =>
            item.separator ? (
              <div key={i} style={{ height: 1, background: 'var(--nv-border)', margin: '4px 0' }} />
            ) : (
              <button
                key={i}
                disabled={item.disabled}
                onClick={() => { item.onClick(); setOpen(false); }}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 8,
                  width: '100%',
                  padding: '6px 14px',
                  fontSize: 12,
                  background: 'transparent',
                  border: 'none',
                  cursor: item.disabled ? 'not-allowed' : 'pointer',
                  color: item.disabled ? 'var(--nv-textMuted)' : 'var(--nv-text)',
                  textAlign: 'left',
                  transition: 'background 0.1s',
                }}
                onMouseEnter={(e) => { if (!item.disabled) (e.currentTarget as HTMLElement).style.background = 'var(--nv-hover)'; }}
                onMouseLeave={(e) => { (e.currentTarget as HTMLElement).style.background = 'transparent'; }}
              >
                <span style={{ color: item.disabled ? 'var(--nv-textMuted)' : 'var(--nv-textSubtle)', flexShrink: 0 }}>{item.icon}</span>
                {item.label}
              </button>
            )
          )}
        </div>
      )}
    </div>
  );
}

// ─── Toolbar Button ──────────────────────────────────────────────────────────
function TbBtn({ icon, label, onClick, disabled = false, hasArrow = false, active = false }: {
  icon: React.ReactNode; label: string; onClick?: () => void; disabled?: boolean; hasArrow?: boolean; active?: boolean;
}) {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      title={label}
      style={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        gap: 2,
        padding: '4px 8px',
        minWidth: 46,
        background: 'transparent',
        border: 'none',
        borderRadius: 4,
        cursor: disabled ? 'not-allowed' : 'pointer',
        opacity: disabled ? 0.45 : 1,
        color: active ? 'var(--nv-accent)' : 'var(--nv-text)',
        transition: 'background 0.1s, color 0.1s',
        position: 'relative',
      }}
      onMouseEnter={(e) => { if (!disabled) (e.currentTarget as HTMLElement).style.background = 'var(--nv-hover)'; }}
      onMouseLeave={(e) => { (e.currentTarget as HTMLElement).style.background = 'transparent'; }}
    >
      <span style={{ display: 'flex', alignItems: 'center', gap: 2 }}>
        {icon}
        {hasArrow && <ChevronDown size={9} style={{ opacity: 0.6, marginTop: 1 }} />}
      </span>
      <span style={{ fontSize: 9, whiteSpace: 'nowrap', lineHeight: 1, color: 'var(--nv-textSubtle)' }}>{label}</span>
    </button>
  );
}

function Sep() {
  return <div style={{ width: 1, height: 36, background: 'var(--nv-border)', margin: '0 2px', alignSelf: 'center' }} />;
}

// ─── AppHeader ────────────────────────────────────────────────────────────────
export function AppHeader({
  activeConn,
  onLogout,
  onNewConnection,
  onNewQuery,
  onNewDatabase,
  onUsers,
  onOpenBackup,
  onOpenRestore,
  onBackupHistory,
  onScheduledJobs,
  onProcessList,
  onServerInfo,
  onAuditLog,
  onSystemUpdate,
  onDataTransfer,
  onDataDiff,
  onER,
  onOsTerminal,
}) {
  const { theme, toggle: toggleTheme } = useThemeStore();
  const openSettings = useSettingsModalStore(s => s.openSettings);
  const { data: meData } = useQuery({ queryKey: ['me'], queryFn: () => api.me(), staleTime: 60000 });
  const isAdmin = meData?.user?.role === 'admin';
  const hasConn = !!activeConn;
  const isMobile = useIsMobile();

  function openDpa() {
    useWorkspaceStore.getState().openTab({ type: 'dpaHome', title: 'DPA Home' });
  }

  const newItems: MenuItem[] = [
    { icon: <Link2 size={13} />, label: 'New Connection', onClick: () => onNewConnection?.() },
    { icon: <Database size={13} />, label: 'New Database', onClick: () => onNewDatabase?.(), disabled: !hasConn },
    { icon: <Code2 size={13} />, label: 'New Query', onClick: () => onNewQuery?.(), disabled: !hasConn },
  ];

  const backupItems: MenuItem[] = [
    { icon: <Archive size={13} />, label: 'Backup', onClick: () => onOpenBackup?.(), disabled: !hasConn },
    { icon: <RotateCcw size={13} />, label: 'Restore', onClick: () => onOpenRestore?.(), disabled: !hasConn },
    { icon: <Clock size={13} />, label: 'History', onClick: () => onBackupHistory?.(), disabled: !hasConn },
    ...(!isLiteEdition ? [
      { separator: true } as any,
      { icon: <CalendarClock size={13} />, label: 'Schedule', onClick: () => onScheduledJobs?.(), disabled: !isAdmin },
    ] : []),
  ];

  const watchItems: MenuItem[] = [
    { icon: <Activity size={13} />, label: 'Processes', onClick: () => onProcessList?.(), disabled: !hasConn },
    { icon: <Info size={13} />, label: 'Server Info', onClick: () => onServerInfo?.(), disabled: !hasConn },
    { icon: <ShieldCheck size={13} />, label: 'Audit', onClick: () => onAuditLog?.(), disabled: !isAdmin || !hasConn },
    ...(!isLiteEdition ? [
      { separator: true } as any,
      { icon: <UploadCloud size={13} />, label: 'Update', onClick: () => onSystemUpdate?.(), disabled: !isAdmin },
    ] : []),
  ];

  const dataItems: MenuItem[] = [
    { icon: <ArrowLeftRight size={13} />, label: 'Data Transfer', onClick: () => onDataTransfer?.(), disabled: !hasConn },
    { icon: <GitCompare size={13} />, label: 'Data Diff', onClick: () => onDataDiff?.(), disabled: !hasConn },
    { icon: <Network size={13} />, label: 'ER Model', onClick: () => onER?.(), disabled: !hasConn },
  ];

  // Combined overflow menu for phone width
  const mobileItems: MenuItem[] = [
    ...(!isLiteEdition ? [
      { icon: <Home size={13} />, label: 'Home', onClick: openDpa },
      { separator: true } as any,
    ] : []),
    ...newItems,
    { separator: true } as any,
    { icon: <UserCircle size={13} />, label: 'User Admin', onClick: () => hasConn && onUsers?.(), disabled: !hasConn },
    { separator: true } as any,
    ...backupItems,
    { separator: true } as any,
    ...watchItems,
    { separator: true } as any,
    ...dataItems,
    ...(!isLiteEdition ? [
      { separator: true } as any,
      { icon: <TerminalSquare size={13} />, label: 'Shell', onClick: () => onOsTerminal?.(), disabled: !isAdmin },
    ] : []),
  ];

  return (
    <header style={{
      height: isMobile ? 52 : 64,
      background: 'var(--nv-toolbar)',
      borderBottom: '1px solid var(--nv-border)',
      display: 'flex',
      alignItems: 'center',
      padding: '0 8px',
      gap: 0,
      flexShrink: 0,
    }}>
      {/* Logo / App identity */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: 8,
        padding: '0 12px 0 4px', marginRight: 4,
        borderRight: '1px solid var(--nv-border)', height: '100%',
      }}>
        <div style={{
          width: 30, height: 30, borderRadius: 6,
          background: 'var(--nv-accent)',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          flexShrink: 0,
        }}>
          <ServerCrash size={16} color="white" />
        </div>
        {!isMobile && (
          <div style={{ lineHeight: 1.3 }}>
            <div style={{ fontWeight: 700, fontSize: 13, color: 'var(--nv-text)' }}>{appConfig.appTitle}</div>
            <div style={{ fontSize: 9, color: 'var(--nv-textSubtle)' }}>{appConfig.appSubtitle}</div>
          </div>
        )}
      </div>

      {/* ── Toolbar buttons ── */}
      {isMobile ? (
        <div style={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <DropdownMenu items={mobileItems} align="left">
            <TbBtn icon={<Menu size={18} />} label="Menu" hasArrow />
          </DropdownMenu>
        </div>
      ) : (
        <div style={{ display: 'flex', alignItems: 'center', gap: 1 }}>

          {!isLiteEdition && (
            <>
              {/* Home → DPA */}
              <TbBtn icon={<Home size={17} />} label="Home" onClick={openDpa} />
              <Sep />
            </>
          )}

          {/* + New */}
          <DropdownMenu items={newItems}>
            <TbBtn icon={<Plus size={17} />} label="New" hasArrow />
          </DropdownMenu>

          <Sep />

          {/* Users */}
          <TbBtn
            icon={<UserCircle size={17} />}
            label="User Admin"
            onClick={() => hasConn && onUsers?.()}
            disabled={!hasConn}
          />

          {/* Backup dropdown */}
          <DropdownMenu items={backupItems}>
            <TbBtn icon={<Archive size={17} />} label="Backup" hasArrow disabled={!hasConn} />
          </DropdownMenu>

          <Sep />

          {/* Watch dropdown */}
          <DropdownMenu items={watchItems}>
            <TbBtn icon={<Eye size={17} />} label="Watch" hasArrow disabled={!hasConn} />
          </DropdownMenu>

          {/* Data dropdown */}
          <DropdownMenu items={dataItems}>
            <TbBtn icon={<Database size={17} />} label="Data" hasArrow disabled={!hasConn} />
          </DropdownMenu>

          <Sep />

          {!isLiteEdition && (
            /* OS Terminal (host shell) — admin only */
            <TbBtn
              icon={<TerminalSquare size={17} />}
              label="Shell"
              onClick={() => onOsTerminal?.()}
              disabled={!isAdmin}
            />
          )}

        </div>
      )}

      {/* Right side */}
      <div style={{ marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: isMobile ? 4 : 8, paddingRight: 8 }}>
        {!isLiteEdition && (
          <ServiceStatusGroup>
            <SchedulerStatusBadge />
            <NotificationStatusBadge />
          </ServiceStatusGroup>
        )}
        <VpnBadge connection={activeConn} />
        <button
          onClick={() => openSettings('general')}
          className="nv-btn !py-1.5"
          title="Settings (Ctrl+,)"
        >
          <Settings2 size={12} />
        </button>
        <button
          onClick={toggleTheme}
          className="nv-btn !py-1.5"
          title="Toggle theme"
        >
          {theme === 'light' ? <Moon size={12} /> : <Sun size={12} />}
        </button>
        <button onClick={onLogout} className="nv-btn !py-1.5" title="Sign Out" style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
          <LogOut size={12} /> {!isMobile && 'Sign Out'}
        </button>
      </div>
    </header>
  );
}
