// @ts-nocheck
// Pure helpers for the OS terminal split-pane tree. No React, no xterm.

export type SplitDir = 'row' | 'col';

export type PaneNode =
  | { id: string; kind: 'leaf' }
  | { id: string; kind: 'split'; dir: SplitDir; ratio: number; children: [PaneNode, PaneNode] };

let _seq = 0;
export function newPaneId(): string {
  _seq += 1;
  return `pane-${Date.now().toString(36)}-${_seq}`;
}

export function leaf(id: string = newPaneId()): PaneNode {
  return { id, kind: 'leaf' };
}

export function findLeaf(root: PaneNode, id: string): PaneNode | null {
  if (root.kind === 'leaf') return root.id === id ? root : null;
  for (const c of root.children) {
    const f = findLeaf(c, id);
    if (f) return f;
  }
  return null;
}

export function walkLeaves(root: PaneNode): PaneNode[] {
  if (root.kind === 'leaf') return [root];
  return [...walkLeaves(root.children[0]), ...walkLeaves(root.children[1])];
}

export function leafCount(root: PaneNode): number {
  return walkLeaves(root).length;
}

/** Replace the leaf `id` with a split containing the old leaf and a fresh one. */
export function splitLeaf(root: PaneNode, id: string, dir: SplitDir): PaneNode {
  if (root.kind === 'leaf') {
    if (root.id !== id) return root;
    return {
      id: newPaneId(),
      kind: 'split',
      dir,
      ratio: 0.5,
      children: [leaf(id), leaf()],
    };
  }
  return { ...root, children: [splitLeaf(root.children[0], id, dir), splitLeaf(root.children[1], id, dir)] };
}

/** Remove a leaf. The sibling subtree collapses up into the parent's place. */
export function removeLeaf(root: PaneNode, id: string): PaneNode {
  if (root.kind === 'leaf') return root;
  const [a, b] = root.children;
  // If the leaf to remove is a direct child, collapse to the sibling.
  if (a.kind === 'leaf' && a.id === id) return b;
  if (b.kind === 'leaf' && b.id === id) return a;
  const na = findLeaf(a, id);
  const nb = findLeaf(b, id);
  if (na) return { ...root, children: [removeLeaf(a, id), b] };
  if (nb) return { ...root, children: [a, removeLeaf(b, id)] };
  return root;
}

/** Next leaf id in display order, wrapping around. */
export function nextLeaf(root: PaneNode, id: string): string | null {
  const leaves = walkLeaves(root);
  if (leaves.length === 0) return null;
  const idx = leaves.findIndex((l) => l.id === id);
  if (idx === -1) return leaves[0].id;
  return leaves[(idx + 1) % leaves.length].id;
}

/** Adjust the ratio of the split that owns `id` (the leaf or any ancestor). */
export function setRatio(root: PaneNode, splitId: string, ratio: number): PaneNode {
  if (root.kind === 'leaf') return root;
  const clamped = Math.min(0.9, Math.max(0.1, ratio));
  if (root.id === splitId) return { ...root, ratio: clamped };
  return { ...root, children: [setRatio(root.children[0], splitId, ratio), setRatio(root.children[1], splitId, ratio)] };
}

/** Find the split node whose divider is at/under the given leaf id (nearest ancestor split). */
export function ancestorSplit(root: PaneNode, leafId: string): PaneNode | null {
  if (root.kind === 'leaf') return null;
  if (findLeaf(root.children[0], leafId)) {
    const deeper = ancestorSplit(root.children[0], leafId);
    return deeper ?? root;
  }
  if (findLeaf(root.children[1], leafId)) {
    const deeper = ancestorSplit(root.children[1], leafId);
    return deeper ?? root;
  }
  return null;
}
