// @ts-nocheck
/** Serialize the active terminal pane to a Markdown document and download it. */
export function exportPaneAsMarkdown(opts: {
  bufferText: () => string;
  shell?: string | null;
  cwd?: string | null;
  tabTitle?: string;
}): void {
  const { bufferText, shell, cwd, tabTitle } = opts;
  const text = (bufferText() || '').replace(/\u0007/g, '').replace(/\x1b\][^\x1b]*\x1b\\/g, '');
  const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);
  const meta: string[] = [`- Fecha: \`${ts}\``];
  if (shell) meta.push(`- Shell: \`${shell}\``);
  if (cwd) meta.push(`- Directorio: \`${cwd}\``);
  if (tabTitle) meta.push(`- Pestaña: ${tabTitle}`);
  const md = [
    `# Terminal SO — ${ts}`,
    '',
    ...meta,
    '',
    '```bash',
    text,
    '```',
    '',
    `_Exportado desde DB Tool Box · Terminal SO._`,
    '',
  ].join('\n');
  const blob = new Blob([md], { type: 'text/markdown;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  const stamp = ts.replace(/[: ]/g, '-');
  a.download = `terminal-${stamp}.md`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

/** Build a shell command to execute a host file in the active pane. */
export function buildRunCommand(relPath: string, scriptsDir: string): string {
  const base = scriptsDir && scriptsDir.startsWith('/')
    ? scriptsDir
    : `$HOME/${scriptsDir || 'scripts'}`;
  const low = relPath.toLowerCase();
  if (low.endsWith('.sh')) return `bash "${base}/${relPath}"`;
  if (low.endsWith('.py')) return `python3 "${base}/${relPath}"`;
  if (low.endsWith('.rb')) return `ruby "${base}/${relPath}"`;
  if (low.endsWith('.pl')) return `perl "${base}/${relPath}"`;
  return `"${base}/${relPath}"`;
}
