// @ts-nocheck
import React from 'react';

/** Project CSS tokens (mirror of DPA panels) for a cohesive look. */
export const T = {
  bg: 'var(--nv-bg)',
  panel: 'var(--nv-panel)',
  sidebar: 'var(--nv-sidebar)',
  toolbar: 'var(--nv-toolbar)',
  border: 'var(--nv-border)',
  borderLight: 'var(--nv-borderLight)',
  hover: 'var(--nv-hover)',
  selected: 'var(--nv-selected)',
  text: 'var(--nv-text)',
  textSubtle: 'var(--nv-textSubtle)',
  textMuted: 'var(--nv-textMuted)',
  accent: 'var(--nv-accent)',
  accentDark: 'var(--nv-accentDark)',
  gridHeader: 'var(--nv-gridHeader)',
  gridAlt: 'var(--nv-gridAlt)',
  danger: 'var(--nv-danger)',
  success: 'var(--nv-success)',
  warning: 'var(--nv-warning)',
};

export const SHADOW_SM = '0 1px 2px rgba(0,0,0,0.20), 0 0 0 1px rgba(0,0,0,0.04)';
export const SHADOW_MD = '0 6px 18px rgba(0,0,0,0.35)';
export const RADIUS = 8;

/** A bordered, rounded card consistent with DPA panels. */
export function Card({ children, style, className }: { children: React.ReactNode; style?: React.CSSProperties; className?: string }) {
  return (
    <div
      className={className}
      style={{
        background: T.panel,
        border: `1px solid ${T.borderLight}`,
        borderRadius: RADIUS,
        boxShadow: SHADOW_SM,
        ...style,
      }}
    >
      {children}
    </div>
  );
}

/** Small uppercase section label with a subtle track. */
export function SectionLabel({ children, style }: { children: React.ReactNode; style?: React.CSSProperties }) {
  return (
    <div
      style={{
        fontSize: 10,
        fontWeight: 600,
        textTransform: 'uppercase',
        letterSpacing: '0.06em',
        color: T.textMuted,
        ...style,
      }}
    >
      {children}
    </div>
  );
}

/** Pill/badge with optional color. */
export function Badge({ children, color, bg, title }: { children: React.ReactNode; color?: string; bg?: string; title?: string }) {
  return (
    <span
      title={title}
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        gap: 4,
        padding: '1px 7px',
        fontSize: 10,
        fontWeight: 600,
        borderRadius: 999,
        color: color ?? T.text,
        background: bg ?? T.gridHeader,
        border: `1px solid ${T.borderLight}`,
        whiteSpace: 'nowrap',
      }}
    >
      {children}
    </span>
  );
}

/** Toolbar button: icon + optional label, with active state. */
export function ToolButton({
  icon, label, onClick, title, active, disabled, danger,
}: {
  icon?: React.ReactNode; label?: string; onClick?: () => void;
  title?: string; active?: boolean; disabled?: boolean; danger?: boolean;
}) {
  return (
    <button
      onClick={onClick}
      title={title}
      disabled={disabled}
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        gap: 5,
        height: 24,
        padding: label ? '0 8px' : '0 6px',
        fontSize: 11,
        fontWeight: 500,
        color: danger ? T.danger : active ? T.accent : T.textSubtle,
        background: active ? T.hover : 'transparent',
        border: `1px solid ${active ? T.accent : 'transparent'}`,
        borderRadius: 5,
        cursor: disabled ? 'not-allowed' : 'pointer',
        opacity: disabled ? 0.45 : 1,
        transition: 'all 0.12s ease',
      }}
      onMouseEnter={(e) => { if (!disabled && !active) { e.currentTarget.style.background = T.hover; e.currentTarget.style.color = T.text; } }}
      onMouseLeave={(e) => { if (!disabled && !active) { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = danger ? T.danger : T.textSubtle; } }}
    >
      {icon}
      {label && <span>{label}</span>}
    </button>
  );
}

/** Thin vertical separator between toolbar groups. */
export function ToolDivider() {
  return <span style={{ width: 1, height: 16, background: T.borderLight, display: 'inline-block', margin: '0 2px' }} />;
}

/** Primary accent button (e.g. Guardar). */
export function PrimaryButton({ children, onClick, disabled, title }: { children: React.ReactNode; onClick?: () => void; disabled?: boolean; title?: string }) {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      title={title}
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        gap: 6,
        height: 26,
        padding: '0 12px',
        fontSize: 11,
        fontWeight: 600,
        color: '#fff',
        background: T.accent,
        border: `1px solid ${T.accent}`,
        borderRadius: 5,
        cursor: disabled ? 'not-allowed' : 'pointer',
        opacity: disabled ? 0.5 : 1,
      }}
    >
      {children}
    </button>
  );
}

/** Ghost button used in drawers (new / upload / etc). Accepts icon + label. */
export function GhostButton({
  icon, label, onClick, title, disabled, danger, children,
}: {
  icon?: React.ReactNode; label?: string; onClick?: () => void;
  title?: string; disabled?: boolean; danger?: boolean; children?: React.ReactNode;
}) {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      title={title}
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        gap: 5,
        height: 24,
        padding: label ? '0 8px' : '0 6px',
        fontSize: 11,
        fontWeight: 500,
        color: danger ? T.danger : T.textSubtle,
        background: T.panel,
        border: `1px solid ${T.borderLight}`,
        borderRadius: 5,
        cursor: disabled ? 'not-allowed' : 'pointer',
        opacity: disabled ? 0.5 : 1,
      }}
      onMouseEnter={(e) => { if (!disabled) { e.currentTarget.style.background = T.hover; e.currentTarget.style.color = danger ? T.danger : T.text; e.currentTarget.borderColor = T.border; } }}
      onMouseLeave={(e) => { if (!disabled) { e.currentTarget.style.background = T.panel; e.currentTarget.style.color = danger ? T.danger : T.textSubtle; e.currentTarget.borderColor = T.borderLight; } }}
    >
      {icon}
      {label && <span>{label}</span>}
      {children}
    </button>
  );
}

/** Styled text input. */
export function TextInput(props: React.InputHTMLAttributes<HTMLInputElement>) {
  const { style, ...rest } = props;
  return (
    <input
      {...rest}
      style={{
        height: 26,
        padding: '0 8px',
        fontSize: 11,
        color: T.text,
        background: T.bg,
        border: `1px solid ${T.borderLight}`,
        borderRadius: 5,
        outline: 'none',
        ...style,
      }}
    />
  );
}

/** Styled textarea. */
export function TextArea(props: React.TextareaHTMLAttributes<HTMLTextAreaElement>) {
  const { style, ...rest } = props;
  return (
    <textarea
      {...rest}
      style={{
        padding: '8px',
        fontSize: 12,
        fontFamily: 'SF Mono, Menlo, Monaco, Consolas, monospace',
        color: T.text,
        background: T.bg,
        border: `1px solid ${T.borderLight}`,
        borderRadius: 5,
        outline: 'none',
        resize: 'vertical',
        ...style,
      }}
    />
  );
}

/** Context menu (right-click) styled to match the dark theme. */
export function ContextMenu({ x, y, items, onClose }: {
  x: number; y: number;
  items: { label: string; icon?: React.ReactNode; danger?: boolean; onClick: () => void }[];
  onClose: () => void;
}) {
  return (
    <>
      <div style={{ position: 'fixed', inset: 0, zIndex: 49 }} onClick={onClose} onContextMenu={(e) => { e.preventDefault(); onClose(); }} />
      <div
        style={{
          position: 'fixed',
          left: Math.min(x, window.innerWidth - 210),
          top: Math.min(y, window.innerHeight - 40 - items.length * 28),
          zIndex: 50,
          minWidth: 190,
          padding: '4px',
          background: T.panel,
          border: `1px solid ${T.border}`,
          borderRadius: 6,
          boxShadow: SHADOW_MD,
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {items.map((it, i) => (
          <button
            key={i}
            onClick={() => { it.onClick(); onClose(); }}
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 8,
              width: '100%',
              padding: '6px 8px',
              fontSize: 12,
              color: it.danger ? T.danger : T.text,
              background: 'transparent',
              border: 'none',
              borderRadius: 4,
              cursor: 'pointer',
              textAlign: 'left',
            }}
            onMouseEnter={(e) => { e.currentTarget.style.background = it.danger ? 'rgba(248,113,113,0.12)' : T.hover; }}
            onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; }}
          >
            <span style={{ display: 'inline-flex', width: 14, justifyContent: 'center' }}>{it.icon}</span>
            {it.label}
          </button>
        ))}
      </div>
    </>
  );
}

/** A chip/tag with optional color. */
export function Chip({ children, color }: { children: React.ReactNode; color?: string }) {
  return (
    <span
      style={{
        display: 'inline-flex',
        alignItems: 'center',
        padding: '1px 7px',
        fontSize: 10,
        fontWeight: 500,
        color: color ?? T.textSubtle,
        background: T.gridHeader,
        border: `1px solid ${T.borderLight}`,
        borderRadius: 4,
        whiteSpace: 'nowrap',
      }}
    >
      {children}
    </span>
  );
}
