import { create } from 'zustand';

type MenuEvent = { clientX: number; clientY: number; preventDefault?: () => void };

export const useContextMenuStore = create((set) => ({
  open: false,
  x: 0,
  y: 0,
  items: [],
  show: (event: MenuEvent | React.MouseEvent, items: any[]) => {
    event?.preventDefault?.();
    set({
      open: true,
      x: event.clientX ?? 0,
      y: event.clientY ?? 0,
      items,
    });
  },
  showAt: (x: number, y: number, items: any[]) => {
    set({ open: true, x, y, items });
  },
  showAtElement: (el: HTMLElement, items: any[]) => {
    const rect = el.getBoundingClientRect();
    set({
      open: true,
      x: Math.min(rect.right - 8, window.innerWidth - 220),
      y: Math.min(rect.bottom + 4, window.innerHeight - 200),
      items,
    });
  },
  hide: () => set({ open: false }),
}));
