// @ts-nocheck
import React, { useState } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { RefreshCw, Play, Power, PowerOff, Trash2 } from 'lucide-react';
import { api } from '../../lib/api';
import { notify, notifyError, confirm } from '../../lib/notify';

export function DbJobsPanel({ connectionId, connectionName, engine }) {
  const qc = useQueryClient();
  const [selectedDb, setSelectedDb] = useState('');
  const [detailId, setDetailId] = useState(null);

  const { data: dbList } = useQuery({
    queryKey: ['dbs', connectionId],
    queryFn: () => api.databases(connectionId),
    enabled: engine === 'mysql',
  });
  const dbs = Array.isArray(dbList) ? dbList : (dbList?.databases ?? []);

  const { data, isFetching, refetch } = useQuery({
    queryKey: ['db-jobs', connectionId, selectedDb],
    queryFn: () => api.dbJobs(connectionId, selectedDb || undefined),
    enabled: !!connectionId,
  });

  const jobs = data?.jobs ?? [];
  const pgCronMissing = data?.pg_cron_missing === true;

  const { data: detail } = useQuery({
    queryKey: ['db-job', connectionId, detailId],
    queryFn: () => api.dbJob(connectionId, detailId),
    enabled: !!detailId,
  });

  const { data: historyData } = useQuery({
    queryKey: ['db-job-history', connectionId, detailId],
    queryFn: () => api.dbJobHistory(connectionId, detailId),
    enabled: !!detailId,
  });

  const invalidate = () => {
    qc.invalidateQueries({ queryKey: ['db-jobs', connectionId] });
    if (detailId) qc.invalidateQueries({ queryKey: ['db-job', connectionId, detailId] });
  };

  const onEnable = async (job) => {
    try {
      await api.dbJobEnable(connectionId, job.jobId);
      notify('Job enabled');
      invalidate();
    } catch (e) {
      notifyError(e);
    }
  };

  const onDisable = async (job) => {
    try {
      await api.dbJobDisable(connectionId, job.jobId);
      notify('Job disabled');
      invalidate();
    } catch (e) {
      notifyError(e);
    }
  };

  const onDrop = async (job) => {
    if (!(await confirm(`Drop job "${job.name}"?`, 'Drop DB Job'))) return;
    try {
      await api.dbJobDrop(connectionId, job.jobId);
      notify('Job dropped');
      setDetailId(null);
      invalidate();
    } catch (e) {
      notifyError(e);
    }
  };

  const onRun = async (job) => {
    try {
      await api.dbJobRun(connectionId, job.jobId);
      notify('Run requested');
      invalidate();
    } catch (e) {
      notifyError(e);
    }
  };

  return (
    <div className="h-full flex flex-col">
      <div className="flex items-center gap-2 px-2 py-1.5 bg-nv-toolbar border-b border-nv-border">
        <span className="font-semibold text-xs">DB Jobs — {connectionName}</span>
        {engine === 'mysql' && (
          <select
            className="nv-input text-xs ml-2 max-w-[180px]"
            value={selectedDb}
            onChange={(e) => setSelectedDb(e.target.value)}
          >
            <option value="">All databases</option>
            {dbs.map((d) => (
              <option key={d} value={d}>{d}</option>
            ))}
          </select>
        )}
        <button type="button" className="nv-btn ml-auto" onClick={() => refetch()}>
          <RefreshCw size={11} className={isFetching ? 'animate-spin' : ''} /> Refresh
        </button>
      </div>

      {pgCronMissing && (
        <div className="px-3 py-2 text-xs bg-yellow-900/20 text-yellow-500 border-b border-nv-border">
          pg_cron extension not detected. Install pg_cron on the server to manage PostgreSQL cron jobs here.
        </div>
      )}

      {engine === 'mongodb' && (
        <div className="px-3 py-2 text-xs text-nv-textSubtle border-b border-nv-border">
          App Jobs scheduled in Navicat for this connection (see header Scheduled Jobs for all).
        </div>
      )}

      <div className="flex flex-1 min-h-0">
        <div className="flex-1 overflow-auto">
          <table className="w-full text-xs">
            <thead className="sticky top-0 bg-nv-gridHeader border-b border-nv-border">
              <tr>
                <th className="text-left px-2 py-1.5">Name</th>
                <th className="text-left px-2 py-1.5">Database</th>
                <th className="text-left px-2 py-1.5">Type</th>
                <th className="text-left px-2 py-1.5">Schedule</th>
                <th className="text-left px-2 py-1.5">Status</th>
                <th className="text-left px-2 py-1.5">Last run</th>
                <th className="text-right px-2 py-1.5">Actions</th>
              </tr>
            </thead>
            <tbody>
              {jobs.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-3 py-6 text-center text-nv-textMuted">
                    {isFetching ? 'Loading…' : 'No database jobs found'}
                  </td>
                </tr>
              )}
              {jobs.map((job) => (
                <tr
                  key={job.jobId}
                  className={`border-b border-nv-borderLight hover:bg-nv-hover cursor-pointer ${detailId === job.jobId ? 'bg-nv-selected' : ''}`}
                  onClick={() => setDetailId(job.jobId)}
                >
                  <td className="px-2 py-1 font-medium">{job.name}</td>
                  <td className="px-2 py-1">{job.database || '—'}</td>
                  <td className="px-2 py-1">
                    <span className="px-1 py-0.5 rounded bg-nv-accent/20 text-nv-accent text-2xs">{job.jobType}</span>
                  </td>
                  <td className="px-2 py-1 font-mono text-2xs text-nv-textSubtle max-w-[200px] truncate" title={job.schedule}>{job.schedule || '—'}</td>
                  <td className="px-2 py-1">
                    <span className={job.enabled ? 'text-nv-success' : 'text-nv-textMuted'}>{job.status}</span>
                  </td>
                  <td className="px-2 py-1 font-mono text-2xs">{job.lastExecuted ? new Date(job.lastExecuted).toLocaleString() : '—'}</td>
                  <td className="px-2 py-1 text-right" onClick={(e) => e.stopPropagation()}>
                    <div className="flex gap-1 justify-end">
                      {job.jobType === 'App Job' && (
                        <button type="button" className="nv-btn !px-1.5" title="Run now" onClick={() => onRun(job)}>
                          <Play size={11} />
                        </button>
                      )}
                      {job.enabled ? (
                        <button type="button" className="nv-btn !px-1.5" title="Disable" onClick={() => onDisable(job)}>
                          <PowerOff size={11} />
                        </button>
                      ) : (
                        <button type="button" className="nv-btn !px-1.5" title="Enable" onClick={() => onEnable(job)}>
                          <Power size={11} />
                        </button>
                      )}
                      <button type="button" className="nv-btn !px-1.5 text-nv-danger" title="Drop" onClick={() => onDrop(job)}>
                        <Trash2 size={11} />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {detailId && detail && (
          <div className="w-[380px] border-l border-nv-border flex flex-col bg-nv-panel shrink-0">
            <div className="px-2 py-1.5 border-b border-nv-border font-semibold text-xs">{detail.name}</div>
            <div className="flex-1 overflow-auto p-2 text-xs space-y-2">
              <div><span className="text-nv-textSubtle">Schedule:</span> {detail.schedule}</div>
              <div><span className="text-nv-textSubtle">Status:</span> {detail.status}</div>
              <pre className="p-2 bg-nv-bg rounded border border-nv-border text-2xs font-mono whitespace-pre-wrap max-h-48 overflow-auto">{detail.definition}</pre>
              {historyData?.note && <p className="text-nv-textMuted text-2xs">{historyData.note}</p>}
              {(historyData?.history ?? []).map((h, i) => (
                <div key={i} className="border-t border-nv-borderLight pt-1 font-mono text-2xs">
                  {h.lastExecuted ? new Date(h.lastExecuted).toLocaleString() : '—'} — {h.status ?? h.note}
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
