// @ts-nocheck
import { useCallback, useRef } from 'react';
import { useContextMenuStore } from '../store/context-menu';

const LONG_PRESS_MS = 450;
const MOVE_THRESHOLD = 10;

type MenuItems = any[] | (() => any[]);

function resolveItems(items: MenuItems) {
  return typeof items === 'function' ? items() : items;
}

/** Non-hook helper for bundle.jsx and legacy components. */
export function bindContextMenuHandlers(items: MenuItems) {
  const show = useContextMenuStore.getState().show;
  let timer: ReturnType<typeof setTimeout> | null = null;
  let startX = 0;
  let startY = 0;

  const clearTimer = () => {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
  };

  return {
    onContextMenu: (e: React.MouseEvent) => {
      e.preventDefault();
      show(e, resolveItems(items));
    },
    onTouchStart: (e: React.TouchEvent) => {
      const t = e.touches[0];
      if (!t) return;
      startX = t.clientX;
      startY = t.clientY;
      clearTimer();
      timer = setTimeout(() => {
        timer = null;
        show({ clientX: startX, clientY: startY, preventDefault: () => {} }, resolveItems(items));
      }, LONG_PRESS_MS);
    },
    onTouchMove: (e: React.TouchEvent) => {
      const t = e.touches[0];
      if (!t || !timer) return;
      if (Math.abs(t.clientX - startX) > MOVE_THRESHOLD || Math.abs(t.clientY - startY) > MOVE_THRESHOLD) {
        clearTimer();
      }
    },
    onTouchEnd: () => clearTimer(),
    onTouchCancel: () => clearTimer(),
  };
}

export function useContextMenuTrigger(items: MenuItems) {
  const show = useContextMenuStore((s) => s.show);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const startRef = useRef({ x: 0, y: 0 });

  const clearTimer = useCallback(() => {
    if (timerRef.current) {
      clearTimeout(timerRef.current);
      timerRef.current = null;
    }
  }, []);

  const onContextMenu = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    show(e, resolveItems(items));
  }, [show, items]);

  const onTouchStart = useCallback((e: React.TouchEvent) => {
    const t = e.touches[0];
    if (!t) return;
    startRef.current = { x: t.clientX, y: t.clientY };
    clearTimer();
    timerRef.current = setTimeout(() => {
      timerRef.current = null;
      const { x, y } = startRef.current;
      show({ clientX: x, clientY: y, preventDefault: () => {} }, resolveItems(items));
    }, LONG_PRESS_MS);
  }, [show, items, clearTimer]);

  const onTouchMove = useCallback((e: React.TouchEvent) => {
    const t = e.touches[0];
    if (!t || !timerRef.current) return;
    const { x, y } = startRef.current;
    if (Math.abs(t.clientX - x) > MOVE_THRESHOLD || Math.abs(t.clientY - y) > MOVE_THRESHOLD) {
      clearTimer();
    }
  }, [clearTimer]);

  const onTouchEnd = useCallback(() => clearTimer(), [clearTimer]);
  const onTouchCancel = useCallback(() => clearTimer(), [clearTimer]);

  const openMenu = useCallback((el?: HTMLElement | null) => {
    if (el) {
      useContextMenuStore.getState().showAtElement(el, resolveItems(items));
      return;
    }
    show({ clientX: window.innerWidth / 2, clientY: 80, preventDefault: () => {} }, resolveItems(items));
  }, [show, items]);

  return { onContextMenu, onTouchStart, onTouchMove, onTouchEnd, onTouchCancel, openMenu };
}
