// @ts-nocheck
import { keepPreviousData } from '@tanstack/react-query';

/** React Query defaults for snapshot-backed panels (instant paint, background refresh). */
export const CACHE_FIRST_QUERY = {
  staleTime: 60_000,
  gcTime: 600_000,
  placeholderData: keepPreviousData,
  refetchOnWindowFocus: false,
};

/** True when the first fetch is in flight and there is nothing to show yet. */
export function isInitialLoad(isLoading: boolean, data: unknown) {
  return isLoading && data == null;
}
