/* Scheduled jobs — v1.2 */
// @ts-nocheck

import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../../lib/api';
import { notify, notifyError, confirm } from '../../lib/notify';
import * as Icons from '../../icons';

const CRON_OPTIONS = [
  { value: 'every_15min', label: 'Every 15 minutes' },
  { value: 'hourly', label: 'Hourly' },
  { value: 'daily', label: 'Daily' },
  { value: 'weekly', label: 'Weekly' },
  { value: '0 * * * *', label: 'Cron: top of each hour' },
  { value: '0 0 * * *', label: 'Cron: midnight daily' },
];

export function ScheduledJobsPanel() {
  const qc = useQueryClient();
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState({
    title: '',
    type: 'sql',
    cronExpr: 'daily',
    connectionId: '',
    database: '',
    sql: 'SELECT 1;',
    enabled: true,
  });
  const [runsFor, setRunsFor] = useState(null);

  const { data, isLoading } = useQuery({
    queryKey: ['scheduled-jobs'],
    queryFn: () => api.scheduledJobs(),
  });
  const { data: conns } = useQuery({
    queryKey: ['connections'],
    queryFn: () => api.connections(),
  });
  const { data: runsData } = useQuery({
    queryKey: ['scheduled-runs', runsFor],
    queryFn: () => api.scheduledJobRuns(runsFor),
    enabled: !!runsFor,
  });

  const jobs = data?.jobs ?? [];

  const saveMut = useMutation({
    mutationFn: () => {
      const payload = {
        connectionId: form.connectionId,
        database: form.database || undefined,
        sql: form.type === 'sql' ? form.sql : undefined,
        options: form.type === 'backup' ? { gzip: true } : undefined,
      };
      if (form.type === 'backup') {
        payload.database = form.database;
      }
      const body = {
        title: form.title,
        type: form.type,
        cronExpr: form.cronExpr,
        enabled: form.enabled,
        payload,
      };
      return editing
        ? api.updateScheduledJob(editing, body)
        : api.createScheduledJob(body);
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['scheduled-jobs'] });
      setEditing(null);
      setForm({
        title: '',
        type: 'sql',
        cronExpr: 'daily',
        connectionId: '',
        database: '',
        sql: 'SELECT 1;',
        enabled: true,
      });
      notify('Job saved', 'Scheduled');
    },
    onError: notifyError,
  });

  const deleteMut = useMutation({
    mutationFn: (id) => api.deleteScheduledJob(id),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['scheduled-jobs'] });
      notify('Job deleted', 'Scheduled');
    },
    onError: notifyError,
  });

  const runMut = useMutation({
    mutationFn: (id) => api.runScheduledJobNow(id),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['scheduled-jobs'] });
      if (runsFor) qc.invalidateQueries({ queryKey: ['scheduled-runs', runsFor] });
      notify('Job executed', 'Scheduled');
    },
    onError: notifyError,
  });

  const startEdit = (job) => {
    setEditing(job.id);
    setForm({
      title: job.title,
      type: job.type,
      cronExpr: job.cronExpr,
      connectionId: job.payload?.connectionId ?? '',
      database: job.payload?.database ?? '',
      sql: job.payload?.sql ?? '',
      enabled: job.enabled,
    });
  };

  return (
    <div className="h-full flex flex-col bg-nv-panel text-xs">
      <div className="px-3 py-2 border-b border-nv-border bg-nv-toolbar flex items-center gap-2">
        <Icons.Pe size={14} className="text-nv-accent" />
        <span className="font-semibold">Scheduled jobs</span>
        <span className="text-2xs text-nv-textMuted ml-1">Scheduler interno (guardian 24/7 + heartbeat UI)</span>
      </div>
      <div className="flex-1 flex min-h-0">
        <div className="w-[42%] border-r border-nv-border overflow-y-auto p-3 space-y-3">
          <p className="text-2xs font-semibold uppercase text-nv-textSubtle">{editing ? 'Edit job' : 'New job'}</p>
          <input
            className="nv-input w-full"
            placeholder="Title"
            value={form.title}
            onChange={(e) => setForm((f) => ({ ...f, title: e.target.value }))}
          />
          <select
            className="nv-select w-full"
            value={form.type}
            onChange={(e) => setForm((f) => ({ ...f, type: e.target.value }))}
          >
            <option value="sql">SQL query</option>
            <option value="backup">Backup</option>
          </select>
          <select
            className="nv-select w-full"
            value={form.cronExpr}
            onChange={(e) => setForm((f) => ({ ...f, cronExpr: e.target.value }))}
          >
            {CRON_OPTIONS.map((o) => (
              <option key={o.value} value={o.value}>
                {o.label}
              </option>
            ))}
          </select>
          <select
            className="nv-select w-full"
            value={form.connectionId}
            onChange={(e) => setForm((f) => ({ ...f, connectionId: e.target.value }))}
          >
            <option value="">— connection —</option>
            {(conns ?? []).map((c) => (
              <option key={c.id} value={c.id}>
                {c.name}
              </option>
            ))}
          </select>
          <input
            className="nv-input w-full"
            placeholder="Database"
            value={form.database}
            onChange={(e) => setForm((f) => ({ ...f, database: e.target.value }))}
          />
          {form.type === 'sql' && (
            <textarea
              className="nv-input w-full font-mono min-h-[100px]"
              value={form.sql}
              onChange={(e) => setForm((f) => ({ ...f, sql: e.target.value }))}
            />
          )}
          <label className="flex items-center gap-2">
            <input
              type="checkbox"
              checked={form.enabled}
              onChange={(e) => setForm((f) => ({ ...f, enabled: e.target.checked }))}
            />
            Enabled
          </label>
          <div className="flex gap-2">
            <button
              type="button"
              className="nv-btn-primary"
              disabled={saveMut.isPending || !form.title || !form.connectionId}
              onClick={() => saveMut.mutate()}
            >
              {saveMut.isPending ? 'Saving…' : editing ? 'Update' : 'Create'}
            </button>
            {editing && (
              <button type="button" className="nv-btn" onClick={() => setEditing(null)}>
                Cancel
              </button>
            )}
          </div>
        </div>
        <div className="flex-1 flex flex-col min-w-0">
          <div className="flex-1 overflow-y-auto">
            {isLoading && <p className="p-3 text-nv-textMuted">Loading…</p>}
            {!isLoading && jobs.length === 0 && (
              <p className="p-3 text-nv-textMuted">No scheduled jobs yet.</p>
            )}
            <table className="w-full text-2xs border-collapse">
              <thead className="sticky top-0 bg-nv-gridHeader">
                <tr>
                  <th className="nv-result-th text-left">Title</th>
                  <th className="nv-result-th">Type</th>
                  <th className="nv-result-th">Schedule</th>
                  <th className="nv-result-th">Next</th>
                  <th className="nv-result-th">On</th>
                  <th className="nv-result-th" />
                </tr>
              </thead>
              <tbody>
                {jobs.map((j) => (
                  <tr key={j.id} className="nv-result-row border-b border-nv-borderLight">
                    <td className="nv-result-td font-medium">{j.title}</td>
                    <td className="nv-result-td">{j.type}</td>
                    <td className="nv-result-td font-mono">{j.cronExpr}</td>
                    <td className="nv-result-td text-nv-textMuted">{j.nextRunAt ?? '—'}</td>
                    <td className="nv-result-td">{j.enabled ? 'Yes' : 'No'}</td>
                    <td className="nv-result-td whitespace-nowrap">
                      <button type="button" className="nv-btn !py-0.5 mr-1" onClick={() => runMut.mutate(j.id)}>
                        Run
                      </button>
                      <button type="button" className="nv-btn !py-0.5 mr-1" onClick={() => setRunsFor(j.id)}>
                        Log
                      </button>
                      <button type="button" className="nv-btn !py-0.5 mr-1" onClick={() => startEdit(j)}>
                        Edit
                      </button>
                      <button
                        type="button"
                        className="nv-btn !py-0.5 text-nv-danger"
                        onClick={async () => {
                          if (await confirm('Delete this job?', 'Scheduled')) deleteMut.mutate(j.id);
                        }}
                      >
                        Del
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          {runsFor && (
            <div className="h-40 border-t border-nv-border overflow-y-auto p-2 bg-nv-bg font-mono text-2xs">
              <div className="flex justify-between mb-1">
                <span className="font-semibold">Run history</span>
                <button type="button" className="nv-btn !py-0" onClick={() => setRunsFor(null)}>
                  Close
                </button>
              </div>
              {(runsData?.runs ?? []).map((r) => (
                <div key={r.id} className="mb-2 border-b border-nv-borderLight pb-1">
                  <span className={r.status === 'failed' ? 'text-nv-danger' : 'text-nv-success'}>
                    {r.status}
                  </span>{' '}
                  {r.startedAt} — {r.finishedAt ?? '…'}
                  {r.logText && <pre className="whitespace-pre-wrap mt-0.5 text-nv-textSubtle">{r.logText}</pre>}
                </div>
              ))}
              {!(runsData?.runs ?? []).length && <p className="text-nv-textMuted">No runs yet.</p>}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
