// @ts-nocheck
import { useRef, useEffect } from 'react';
import Editor from '@monaco-editor/react';
import { useThemeStore } from '../../store/theme';

/** Map a filename to a Monaco language id. */
export function languageFromName(name: string): string {
  const low = (name || '').toLowerCase();
  if (low.endsWith('.sh') || low.endsWith('.bash')) return 'shell';
  if (low.endsWith('.py')) return 'python';
  if (low.endsWith('.rb')) return 'ruby';
  if (low.endsWith('.pl')) return 'perl';
  if (low.endsWith('.php')) return 'php';
  if (low.endsWith('.js') || low.endsWith('.mjs') || low.endsWith('.cjs')) return 'javascript';
  if (low.endsWith('.ts') || low.endsWith('.tsx')) return 'typescript';
  if (low.endsWith('.jsx')) return 'javascript';
  if (low.endsWith('.json')) return 'json';
  if (low.endsWith('.yml') || low.endsWith('.yaml')) return 'yaml';
  if (low.endsWith('.sql')) return 'sql';
  if (low.endsWith('.md') || low.endsWith('.markdown')) return 'markdown';
  if (low.endsWith('.xml') || low.endsWith('.html') || low.endsWith('.htm')) return 'xml';
  if (low.endsWith('.css')) return 'css';
  if (low.endsWith('.conf') || low.endsWith('.env') || low.endsWith('.ini')) return 'ini';
  if (low.endsWith('.txt') || low.endsWith('.log')) return 'plaintext';
  return 'plaintext';
}

type Props = {
  path?: string;        // filename, used for language detection + as the model URI
  value: string;
  onChange?: (v: string) => void;
  onSave?: () => void;  // Ctrl/Cmd+S
  readOnly?: boolean;
  height?: number | string;
  fontSize?: number;
  wordWrap?: boolean;
};

export function CodeEditor({
  path, value, onChange, onSave, readOnly, height = 240, fontSize = 12, wordWrap = false,
}: Props) {
  const theme = useThemeStore((s) => s.theme);
  const onSaveRef = useRef(onSave);
  onSaveRef.current = onSave;
  const editorRef = useRef<any>(null);

  // Ctrl/Cmd+S → save (without bubbling to the browser save dialog).
  const handleMount = (editor: any, monaco: any) => {
    editorRef.current = editor;
    editor.addCommand(monaco.KeyMod.CtrlCmd | monaco.KeyCode.KeyS, () => {
      onSaveRef.current?.();
    });
  };

  // Focus when becoming editable / path changes.
  useEffect(() => {
    const t = setTimeout(() => { try { editorRef.current?.focus(); } catch (_) {} }, 30);
    return () => clearTimeout(t);
  }, [path]);

  return (
    <div
      style={{
        height,
        border: '1px solid var(--nv-borderLight)',
        borderRadius: 6,
        overflow: 'hidden',
        background: theme === 'dark' ? '#0b0f17' : '#fff',
      }}
    >
      <Editor
        height="100%"
        path={path ? `file:///${path}` : undefined}
        defaultLanguage={path ? languageFromName(path) : 'plaintext'}
        language={path ? languageFromName(path) : 'plaintext'}
        theme={theme === 'dark' ? 'vs-dark' : 'vs'}
        value={value}
        onChange={(v) => onChange?.(v ?? '')}
        onMount={handleMount}
        loading={<div style={{ padding: 12, fontSize: 11, color: '#888' }}>Cargando editor…</div>}
        options={{
          minimap: { enabled: false },
          fontSize,
          fontFamily: 'SF Mono, Menlo, Monaco, Consolas, "Liberation Mono", monospace',
          fontLigatures: true,
          lineNumbers: 'on',
          renderLineHighlight: 'all',
          scrollBeyondLastLine: false,
          automaticLayout: true,
          tabSize: 2,
          insertSpaces: true,
          wordWrap: wordWrap ? 'on' : 'off',
          readOnly,
          smoothScrolling: true,
          cursorBlinking: 'smooth',
          cursorSmoothCaretAnimation: 'on',
          bracketPairColorization: { enabled: true },
          guides: { bracketPairs: true, indentation: true },
          scrollbar: {
            verticalScrollbarSize: 10,
            horizontalScrollbarSize: 10,
            useShadows: false,
          },
          padding: { top: 8, bottom: 8 },
          overviewRulerLanes: 0,
        }}
      />
    </div>
  );
}
