import { useState, useRef, useEffect, useCallback } from 'react';
import { useIsMobile } from './useIsMobile';

/** Drag handle between top/bottom panels; returns top section height as % of container.
 *  When `mobileStack` is set and the viewport is phone-width, `stacked` becomes true so
 *  the caller can render the panes as a vertical column at full height (no drag handle). */
export function useVerticalSplit(
  initialPct: number,
  opts?: { minPct?: number; maxPct?: number; mobileStack?: boolean }
) {
  const minPct = opts?.minPct ?? 18;
  const maxPct = opts?.maxPct ?? 82;
  const isMobile = useIsMobile();
  const stacked = !!opts?.mobileStack && isMobile;
  const containerRef = useRef<HTMLDivElement>(null);
  const [topPct, setTopPct] = useState(initialPct);
  const dragging = useRef(false);

  const onResizeStart = useCallback((e: React.MouseEvent | React.PointerEvent) => {
    e.preventDefault();
    dragging.current = true;
    document.body.style.cursor = 'row-resize';
    document.body.style.userSelect = 'none';
    (e.target as HTMLElement)?.setPointerCapture?.((e as React.PointerEvent).pointerId);
  }, []);

  useEffect(() => {
    const onMove = (e: MouseEvent | PointerEvent) => {
      if (!dragging.current || !containerRef.current) return;
      const rect = containerRef.current.getBoundingClientRect();
      const p = ((e.clientY - rect.top) / rect.height) * 100;
      setTopPct(Math.round(Math.max(minPct, Math.min(maxPct, p))));
    };
    const onUp = () => {
      if (!dragging.current) return;
      dragging.current = false;
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
    };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
    window.addEventListener('pointermove', onMove);
    window.addEventListener('pointerup', onUp);
    return () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
      window.removeEventListener('pointermove', onMove);
      window.removeEventListener('pointerup', onUp);
    };
  }, [minPct, maxPct]);

  return { containerRef, topPct, stacked, onResizeStart };
}

const QS_LIST_WIDTH_KEY = 'nv-qs-list-width-pct';
const QS_LIST_WIDTH_DEFAULT = 38;

function readStoredPct(key: string, fallback: number, minPct: number, maxPct: number): number {
  try {
    const v = parseFloat(localStorage.getItem(key) || String(fallback));
    if (!Number.isFinite(v)) return fallback;
    return Math.max(minPct, Math.min(maxPct, v));
  } catch {
    return fallback;
  }
}

/** Drag handle between left/right panels; returns left section width as % of container.
 *  When `mobileStack` is set and the viewport is phone-width, `stacked` becomes true so
 *  the caller can render the panes as a vertical stack at full width (no drag handle). */
export function useHorizontalSplit(
  storageKey = QS_LIST_WIDTH_KEY,
  initialPct = QS_LIST_WIDTH_DEFAULT,
  opts?: { minPct?: number; maxPct?: number; mobileStack?: boolean }
) {
  const minPct = opts?.minPct ?? 22;
  const maxPct = opts?.maxPct ?? 58;
  const isMobile = useIsMobile();
  const stacked = !!opts?.mobileStack && isMobile;
  const containerRef = useRef<HTMLDivElement>(null);
  const [leftPct, setLeftPct] = useState(() => readStoredPct(storageKey, initialPct, minPct, maxPct));
  const leftRef = useRef(leftPct);
  leftRef.current = leftPct;
  const dragging = useRef(false);

  const onResizeStart = useCallback((e: React.MouseEvent | React.PointerEvent) => {
    e.preventDefault();
    dragging.current = true;
    document.body.style.cursor = 'col-resize';
    document.body.style.userSelect = 'none';
    (e.target as HTMLElement)?.setPointerCapture?.((e as React.PointerEvent).pointerId);
  }, []);

  useEffect(() => {
    const onMove = (e: MouseEvent | PointerEvent) => {
      if (!dragging.current || !containerRef.current) return;
      const rect = containerRef.current.getBoundingClientRect();
      const p = ((e.clientX - rect.left) / rect.width) * 100;
      setLeftPct(Math.round(Math.max(minPct, Math.min(maxPct, p)) * 10) / 10);
    };
    const onUp = () => {
      if (!dragging.current) return;
      dragging.current = false;
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
      try {
        localStorage.setItem(storageKey, String(leftRef.current));
      } catch {
        /* ignore */
      }
    };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
    window.addEventListener('pointermove', onMove);
    window.addEventListener('pointerup', onUp);
    return () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
      window.removeEventListener('pointermove', onMove);
      window.removeEventListener('pointerup', onUp);
    };
  }, [minPct, maxPct, storageKey]);

  return { containerRef, leftPct, stacked, onResizeStart };
}

const TERM_HEIGHT_KEY = 'nv-terminal-height';
const TERM_HEIGHT_DEFAULT = 288;

function readTermHeight(): number {
  try {
    const v = parseInt(localStorage.getItem(TERM_HEIGHT_KEY) || String(TERM_HEIGHT_DEFAULT), 10);
    if (!Number.isFinite(v)) return TERM_HEIGHT_DEFAULT;
    return Math.max(120, Math.min(560, v));
  } catch {
    return TERM_HEIGHT_DEFAULT;
  }
}

/** Bottom panel (Terminal SQL): drag top edge to change height in px. */
export function useBottomPanelHeight(initialPx = readTermHeight()) {
  const minPx = 120;
  const maxPx = 560;
  const [heightPx, setHeightPx] = useState(initialPx);
  const heightRef = useRef(heightPx);
  heightRef.current = heightPx;
  const dragging = useRef(false);
  const startY = useRef(0);
  const startH = useRef(0);

  const onResizeStart = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      dragging.current = true;
      startY.current = e.clientY;
      startH.current = heightPx;
      document.body.style.cursor = 'row-resize';
      document.body.style.userSelect = 'none';
    },
    [heightPx]
  );

  useEffect(() => {
    const onMove = (e: MouseEvent) => {
      if (!dragging.current) return;
      const delta = startY.current - e.clientY;
      setHeightPx(Math.round(Math.max(minPx, Math.min(maxPx, startH.current + delta))));
    };
    const onUp = () => {
      if (!dragging.current) return;
      dragging.current = false;
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
      try {
        localStorage.setItem(TERM_HEIGHT_KEY, String(heightRef.current));
      } catch {
        /* ignore */
      }
    };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
    return () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
    };
  }, [minPx, maxPx]);

  return { heightPx, onResizeStart };
}

const QS_DETAIL_HEIGHT_KEY = 'nv-qs-detail-height';
const QS_DETAIL_HEIGHT_DEFAULT = 340;

function readStoredHeight(key: string, fallback: number, minPx: number, maxPx: number): number {
  try {
    const v = parseInt(localStorage.getItem(key) || String(fallback), 10);
    if (!Number.isFinite(v)) return fallback;
    return Math.max(minPx, Math.min(maxPx, v));
  } catch {
    return fallback;
  }
}

/** Bottom panel with collapse + drag resize (SQL terminal / Query Store detail). */
export function useCollapsibleBottomPanel(
  storageKey = QS_DETAIL_HEIGHT_KEY,
  defaultPx = QS_DETAIL_HEIGHT_DEFAULT,
  opts?: { minPx?: number; maxPx?: number }
) {
  const minPx = opts?.minPx ?? 120;
  const maxPx = opts?.maxPx ?? 720;
  const [collapsed, setCollapsed] = useState(false);
  const [heightPx, setHeightPx] = useState(() => readStoredHeight(storageKey, defaultPx, minPx, maxPx));
  const heightRef = useRef(heightPx);
  heightRef.current = heightPx;
  const dragging = useRef(false);
  const startY = useRef(0);
  const startH = useRef(0);

  const onResizeStart = useCallback(
    (e: React.MouseEvent) => {
      if (collapsed) return;
      e.preventDefault();
      dragging.current = true;
      startY.current = e.clientY;
      startH.current = heightPx;
      document.body.style.cursor = 'row-resize';
      document.body.style.userSelect = 'none';
    },
    [collapsed, heightPx]
  );

  useEffect(() => {
    const onMove = (e: MouseEvent) => {
      if (!dragging.current) return;
      const delta = startY.current - e.clientY;
      setHeightPx(Math.round(Math.max(minPx, Math.min(maxPx, startH.current + delta))));
    };
    const onUp = () => {
      if (!dragging.current) return;
      dragging.current = false;
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
      try {
        localStorage.setItem(storageKey, String(heightRef.current));
      } catch {
        /* ignore */
      }
    };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
    return () => {
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
    };
  }, [minPx, maxPx, storageKey]);

  const toggle = useCallback(() => setCollapsed((c) => !c), []);

  return { collapsed, setCollapsed, toggle, heightPx, setHeightPx, onResizeStart };
}
