// @ts-nocheck
import React, { useEffect, useMemo } from 'react';
import { X, Settings } from 'lucide-react';
import { useQuery } from '@tanstack/react-query';
import { api } from '../../lib/api';
import { isLiteEdition } from '../../lib/config';
import { useSettingsModalStore, type SettingsSection } from '../../store/settings-modal';
import { useIsMobile } from '../../lib/useIsMobile';
import {
  GeneralSection, NotificationsSection, AlertsSection, BlackoutsSection,
  CorrelationSection, CollectorSection, QueryStoreSection, HealthSection,
  RetentionSection, UsersSection, InfraSection, AiSection, VpnSection,
} from './SettingsSections';

const NAV: { id: SettingsSection; label: string; roles: string[] }[] = [
  { id: 'general', label: 'General', roles: ['viewer', 'dba', 'admin'] },
  { id: 'notifications', label: 'Notifications', roles: ['admin'] },
  { id: 'alerts', label: 'Alerts', roles: ['dba', 'admin'] },
  { id: 'blackouts', label: 'Blackouts', roles: ['dba', 'admin'] },
  { id: 'correlation', label: 'Correlation', roles: ['dba', 'admin'] },
  { id: 'collector', label: 'Collector', roles: ['admin'] },
  { id: 'queryStore', label: 'Query Store', roles: ['dba', 'admin'] },
  { id: 'health', label: 'Health score', roles: ['dba', 'admin'] },
  { id: 'retention', label: 'Retention', roles: ['admin'] },
  { id: 'users', label: 'Users', roles: ['admin'] },
  { id: 'ai', label: 'AI Provider', roles: ['admin'] },
  { id: 'vpn', label: 'VPN', roles: ['admin'] },
  { id: 'infra', label: 'Infrastructure', roles: ['admin'] },
];

export function SettingsModal({ connections = [], inline = false }: { connections?: any[]; inline?: boolean }) {
  const { open, section, closeSettings, setSection } = useSettingsModalStore();
  const me = useQuery({ queryKey: ['me'], queryFn: () => api.me(), staleTime: 60000 });
  const role = me.data?.user?.role ?? 'viewer';
  const isMobile = useIsMobile();

  const visibleNav = useMemo(
    () => NAV.filter(n =>
      n.roles.includes(role)
      && (!isLiteEdition || ['general', 'users', 'vpn'].includes(n.id)),
    ),
    [role],
  );

  useEffect(() => {
    if (!open && !inline) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') closeSettings();
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [open, inline, closeSettings]);

  useEffect(() => {
    if ((open || inline) && !visibleNav.find(n => n.id === section)) {
      setSection(visibleNav[0]?.id ?? 'general');
    }
  }, [open, inline, section, visibleNav, setSection]);

  if (!open && !inline) return null;

  const content = {
    general: <GeneralSection />,
    notifications: <NotificationsSection />,
    alerts: <AlertsSection />,
    blackouts: <BlackoutsSection />,
    correlation: <CorrelationSection />,
    collector: <CollectorSection />,
    queryStore: <QueryStoreSection connections={connections} />,
    health: <HealthSection />,
    retention: <RetentionSection />,
    users: <UsersSection />,
    ai: <AiSection />,
    vpn: <VpnSection />,
    infra: <InfraSection />,
  }[section] ?? <GeneralSection />;

  const shellStyle: React.CSSProperties = inline
    ? { width: '100%', height: '100%', display: 'flex', flexDirection: isMobile ? 'column' : 'row', background: 'var(--nv-toolbar)', border: '1px solid var(--nv-border)', borderRadius: 8, overflow: 'hidden' }
    : isMobile
      ? { width: '100%', height: '100%', display: 'flex', flexDirection: 'column', background: 'var(--nv-toolbar)', borderRadius: 12, boxShadow: '0 24px 64px rgba(0,0,0,0.45)', overflow: 'hidden' }
      : { width: 'min(960px, 100%)', height: 'min(88vh, 720px)', display: 'flex', flexDirection: 'row', background: 'var(--nv-toolbar)', border: '1px solid var(--nv-border)', borderRadius: 12, boxShadow: '0 24px 64px rgba(0,0,0,0.45)', overflow: 'hidden' };

  return (
    <div style={inline ? { width: '100%', height: '100%' } : {
      position: 'fixed', inset: 0, zIndex: 2000, background: 'rgba(0,0,0,0.65)',
      display: 'flex', alignItems: 'center', justifyContent: 'center', padding: isMobile ? 0 : 16,
    }} onClick={inline ? undefined : closeSettings}>
      <div onClick={e => e.stopPropagation()} style={shellStyle}>
        <nav style={{
          width: isMobile ? '100%' : 200, flexShrink: 0,
          borderRight: isMobile ? 'none' : '1px solid var(--nv-border)',
          borderBottom: isMobile ? '1px solid var(--nv-border)' : 'none',
          padding: isMobile ? '8px 8px 8px' : '12px 8px',
          overflowX: isMobile ? 'auto' : 'visible',
          overflowY: isMobile ? 'visible' : 'auto',
          background: 'var(--nv-surface)',
          display: isMobile ? 'flex' : 'block',
          gap: isMobile ? 4 : 0,
          whiteSpace: isMobile ? 'nowrap' : 'normal',
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: isMobile ? '0 6px 0 0' : '4px 8px 12px', fontSize: 13, fontWeight: 700, flexShrink: 0 }}>
            <Settings size={16} /> {isMobile && 'Config'}
            {!isMobile && 'Configuration'}
          </div>
          {visibleNav.map(n => (
            <button key={n.id} type="button" onClick={() => setSection(n.id)} style={{
              width: isMobile ? 'auto' : '100%', textAlign: 'left', padding: isMobile ? '6px 10px' : '8px 10px', marginBottom: isMobile ? 0 : 2, borderRadius: 6,
              border: 'none', cursor: 'pointer', fontSize: 12, fontWeight: section === n.id ? 600 : 400, flexShrink: 0,
              background: section === n.id ? 'var(--nv-accent)' : 'transparent',
              color: section === n.id ? '#fff' : 'var(--nv-textMuted)',
            }}>{n.label}</button>
          ))}
        </nav>
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0 }}>
          <div style={{ display: 'flex', justifyContent: 'flex-end', padding: '8px 12px', borderBottom: '1px solid var(--nv-border)' }}>
            <button type="button" onClick={closeSettings} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--nv-textMuted)' }}>
              <X size={18} />
            </button>
          </div>
          <div style={{ flex: 1, overflowY: 'auto', padding: isMobile ? '12px 12px' : '16px 20px' }}>{content}</div>
        </div>
      </div>
    </div>
  );
}
