// @ts-nocheck
import { useEffect, useState, useRef, useCallback } from 'react';
import { Code2, Plus, RefreshCw, Upload, Play, Pencil, Trash2, X, FileCode } from 'lucide-react';
import { api } from '../../lib/api';
import { T, SHADOW_MD, RADIUS, SectionLabel, Badge, Chip, GhostButton, PrimaryButton, TextInput, ContextMenu } from './ui';
import { CodeEditor, languageFromName } from './CodeEditor';

type Snippet = {
  id: string; name: string; description: string; content: string;
  tags: string; createdBy: string; createdAt: string; updatedAt: string;
};

type Props = { onRun: (text: string) => void; onClose: () => void; width?: number };

const EMPTY = { id: '', name: '', description: '', content: '', tags: '' };
const iconSize = 14;

export function SnippetsDrawer({ onRun, onClose, width }: Props) {
  const fullScreen = width == null;
  const [items, setItems] = useState<Snippet[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [editor, setEditor] = useState(EMPTY);
  const [saving, setSaving] = useState(false);
  const [query, setQuery] = useState('');
  const [menu, setMenu] = useState<{ x: number; y: number; s: Snippet } | null>(null);
  const fileInputRef = useRef<HTMLInputElement | null>(null);

  const load = useCallback(async () => {
    setLoading(true); setError('');
    try { setItems(await api.osTerminalSnippets()); }
    catch (e: any) { setError(e?.message || 'error'); }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { load(); }, [load]);
  useEffect(() => {
    const close = () => setMenu(null);
    if (menu) { window.addEventListener('scroll', close, true); }
    return () => { if (menu) window.removeEventListener('scroll', close, true); };
  }, [menu]);

  const save = async () => {
    if (!editor.name.trim() || !editor.content.trim()) return;
    setSaving(true); setError('');
    try {
      const body = { name: editor.name.trim(), description: editor.description.trim(), content: editor.content, tags: editor.tags.trim() };
      if (editor.id) await api.osTerminalUpdateSnippet(editor.id, body);
      else await api.osTerminalCreateSnippet(body);
      setEditor(EMPTY);
      await load();
    } catch (e: any) { setError(e?.message || 'error'); }
    finally { setSaving(false); }
  };

  const remove = async (s: Snippet) => {
    if (!confirm(`¿Eliminar el snippet "${s.name}"?`)) return;
    try { await api.osTerminalDeleteSnippet(s.id); await load(); }
    catch (e: any) { setError(e?.message || 'error'); }
  };

  const importFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (!f) return;
    const reader = new FileReader();
    reader.onload = () => setEditor((ed) => ({ ...ed, name: ed.name || f.name, content: String(reader.result || '') }));
    reader.readAsText(f);
    e.target.value = '';
  };

  const runSnippet = (s: Snippet) => onRun(s.content.endsWith('\n') ? s.content : s.content + '\n');

  const filtered = items.filter((s) => {
    if (!query.trim()) return true;
    const q = query.toLowerCase();
    return s.name.toLowerCase().includes(q) || s.tags.toLowerCase().includes(q) || s.content.toLowerCase().includes(q);
  });

  const editing = editor.id !== '' || editor.name !== '' || editor.content !== '';

  return (
    <div
      className="shrink-0 flex flex-col min-h-0"
      style={fullScreen
        ? { position: 'absolute', inset: 0, width: '100%', zIndex: 50, background: T.panel, overflow: 'hidden' }
        : { width, background: T.panel, border: `1px solid ${T.borderLight}`, borderRadius: RADIUS, boxShadow: SHADOW_MD, overflow: 'hidden' }}
    >
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '8px 10px', borderBottom: `1px solid ${T.borderLight}`, background: T.toolbar }}>
        <Code2 size={15} style={{ color: T.accent }} />
        <span style={{ fontSize: 12, fontWeight: 700, color: T.text }}>Snippets</span>
        <Badge>{items.length}</Badge>
        <div className="flex-1" />
        <GhostButton icon={<RefreshCw size={12} />} onClick={load} title="Recargar" />
        <GhostButton icon={<Plus size={12} />} label="Nuevo" onClick={() => setEditor(EMPTY)} title="Nuevo snippet" />
        <GhostButton icon={<X size={12} />} onClick={onClose} title="Cerrar" />
      </div>

      {/* Search */}
      <div style={{ padding: '6px 10px', borderBottom: `1px solid ${T.borderLight}` }}>
        <TextInput value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Buscar snippet…" style={{ width: '100%' }} />
      </div>

      {/* Editor */}
      {editing && (
        <div style={{ padding: 10, borderBottom: `1px solid ${T.borderLight}`, display: 'flex', flexDirection: 'column', gap: 6, maxHeight: '55%', overflow: 'auto', background: T.bg }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <SectionLabel>{editor.id ? 'Editar' : 'Nuevo'} snippet</SectionLabel>
            <div className="flex-1" />
            <GhostButton icon={<X size={12} />} onClick={() => setEditor(EMPTY)} title="Cancelar" />
          </div>
          <TextInput value={editor.name} onChange={(e) => setEditor((ed) => ({ ...ed, name: e.target.value }))} placeholder="Nombre" style={{ width: '100%' }} />
          <TextInput value={editor.description} onChange={(e) => setEditor((ed) => ({ ...ed, description: e.target.value }))} placeholder="Descripción (opcional)" style={{ width: '100%' }} />
          <TextInput value={editor.tags} onChange={(e) => setEditor((ed) => ({ ...ed, tags: e.target.value }))} placeholder="tags, separados, por, coma" style={{ width: '100%' }} />
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <SectionLabel>Contenido</SectionLabel>
            <span style={{ fontSize: 10, color: T.textMuted, textTransform: 'uppercase', letterSpacing: '0.05em' }}>{languageFromName(editor.name || 'snippet.txt')}</span>
          </div>
          <CodeEditor
            path={editor.name || 'snippet.txt'}
            value={editor.content}
            onChange={(v) => setEditor((ed) => ({ ...ed, content: v }))}
            onSave={save}
            height={fullScreen ? '60vh' : 170}
          />
          <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginTop: 2 }}>
            <GhostButton icon={<Upload size={12} />} label="Importar" onClick={() => fileInputRef.current?.click()} title="Importar desde archivo" />
            <input ref={fileInputRef} type="file" onChange={importFile} className="hidden" />
            <span style={{ fontSize: 10, color: T.textMuted }}>Ctrl+S guarda</span>
            <div className="flex-1" />
            <PrimaryButton onClick={save} disabled={saving || !editor.name.trim() || !editor.content.trim()}>{saving ? 'Guardando…' : 'Guardar'}</PrimaryButton>
          </div>
        </div>
      )}

      {error && <div style={{ padding: '4px 10px', fontSize: 11, color: T.danger, borderBottom: `1px solid ${T.borderLight}` }}>{error}</div>}

      {/* List */}
      <div className="flex-1 overflow-auto min-h-0" style={{ background: T.bg }}>
        {loading && <div style={{ padding: 10, fontSize: 11, color: T.textMuted }}>Cargando…</div>}
        {!loading && filtered.length === 0 && (
          <div style={{ padding: '16px 10px', fontSize: 11, color: T.textMuted, textAlign: 'center' }}>
            <FileCode size={22} style={{ opacity: 0.4, marginBottom: 6 }} />
            <div>Sin snippets.</div>
            <div style={{ fontSize: 10, marginTop: 2 }}>Crea uno con <strong>+ Nuevo</strong>.</div>
          </div>
        )}
        {filtered.map((s) => (
          <div
            key={s.id}
            className="group"
            style={{ padding: '7px 10px', borderBottom: `1px solid ${T.borderLight}`, cursor: 'pointer' }}
            onClick={() => setEditor({ id: s.id, name: s.name, description: s.description, content: s.content, tags: s.tags })}
            onContextMenu={(e) => { e.preventDefault(); setMenu({ x: e.clientX, y: e.clientY, s }); }}
            onMouseEnter={(e) => { e.currentTarget.style.background = T.hover; }}
            onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; }}
            title="Click = editar · Click derecho = menú"
          >
            <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
              <Play size={12} style={{ color: T.accent, flexShrink: 0 }} />
              <span style={{ fontSize: 12, fontWeight: 600, color: T.text, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', flex: 1 }}>{s.name}</span>
              <span
                onClick={(e) => { e.stopPropagation(); runSnippet(s); }}
                style={{ opacity: 0, transition: 'opacity 0.12s' }}
                className="group-hover:opacity-100"
                title="Ejecutar en pane activo"
              >
                <GhostButton icon={<Play size={12} />} label="Ejecutar" />
              </span>
            </div>
            {s.description && <div style={{ fontSize: 10.5, color: T.textSubtle, marginTop: 2, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{s.description}</div>}
            {s.tags && (
              <div style={{ marginTop: 4, display: 'flex', gap: 4, flexWrap: 'wrap' }}>
                {s.tags.split(',').map((t) => t.trim()).filter(Boolean).map((t) => <Chip key={t}>{t}</Chip>)}
              </div>
            )}
          </div>
        ))}
      </div>

      {menu && (
        <ContextMenu
          x={menu.x} y={menu.y}
          onClose={() => setMenu(null)}
          items={[
            { label: 'Ejecutar en pane activo', icon: <Play size={13} />, onClick: () => runSnippet(menu.s) },
            { label: 'Editar', icon: <Pencil size={13} />, onClick: () => setEditor({ id: menu.s.id, name: menu.s.name, description: menu.s.description, content: menu.s.content, tags: menu.s.tags }) },
            { label: 'Eliminar', icon: <Trash2 size={13} />, danger: true, onClick: () => remove(menu.s) },
          ]}
        />
      )}
    </div>
  );
}
