// @ts-nocheck
import React from 'react';

export const fieldStyle: React.CSSProperties = {
  width: '100%', boxSizing: 'border-box', padding: '6px 8px', borderRadius: 6, fontSize: 12,
  background: 'var(--nv-surface)', border: '1px solid var(--nv-border)', color: 'var(--nv-text)',
};

export const labelStyle: React.CSSProperties = {
  fontSize: 11, fontWeight: 600, color: 'var(--nv-textMuted)', marginBottom: 4, display: 'block',
};

export const sectionTitle: React.CSSProperties = {
  fontSize: 14, fontWeight: 700, color: 'var(--nv-text)', marginBottom: 4,
};

export const sectionDesc: React.CSSProperties = {
  fontSize: 11, color: 'var(--nv-textSubtle)', marginBottom: 14, lineHeight: 1.4,
};

export function SaveBar({ onSave, busy, dirty }: { onSave: () => void; busy?: boolean; dirty?: boolean }) {
  return (
    <div style={{ display: 'flex', gap: 8, marginTop: 16, paddingTop: 12, borderTop: '1px solid var(--nv-border)' }}>
      <button
        type="button"
        disabled={busy || !dirty}
        onClick={onSave}
        style={{
          padding: '6px 14px', borderRadius: 6, fontSize: 12, fontWeight: 600, cursor: busy ? 'wait' : 'pointer',
          background: dirty ? 'var(--nv-accent)' : 'var(--nv-surface)', color: dirty ? '#fff' : 'var(--nv-textMuted)',
          border: '1px solid var(--nv-border)',
        }}
      >
        {busy ? 'Saving…' : 'Save changes'}
      </button>
    </div>
  );
}

export function NumField({ label, value, onChange, min, max, step = 1 }: {
  label: string; value: number; onChange: (v: number) => void; min?: number; max?: number; step?: number;
}) {
  return (
    <label style={{ display: 'block', marginBottom: 10 }}>
      <span style={labelStyle}>{label}</span>
      <input type="number" min={min} max={max} step={step} value={value}
        onChange={e => onChange(Number(e.target.value))} style={fieldStyle} />
    </label>
  );
}
