// @ts-nocheck
import { useEffect, useState, useRef, useCallback } from 'react';
import {
  FolderTree, Folder, FolderOpen, FileCode, Cog, FileText, Home, ChevronRight,
  Plus, Upload, Play, Pencil, Trash2, X,
} from 'lucide-react';
import { api } from '../../lib/api';
import { buildRunCommand } from './terminal-export';
import { T, SHADOW_MD, RADIUS, Badge, GhostButton, PrimaryButton, ContextMenu } from './ui';
import { CodeEditor, languageFromName } from './CodeEditor';

type Entry = { name: string; path: string; isDir: boolean; size: number; mtime: number; executable: boolean };

type Props = { scriptsDir: string; onRun: (text: string) => void; onClose: () => void; width?: number };

function fileIcon(e: Entry) {
  if (e.isDir) return <Folder size={14} style={{ color: T.accent, flexShrink: 0 }} />;
  if (e.executable) return <Cog size={14} style={{ color: T.warning, flexShrink: 0 }} />;
  const low = e.name.toLowerCase();
  if (low.endsWith('.sh') || low.endsWith('.py') || low.endsWith('.rb') || low.endsWith('.pl')) return <FileCode size={14} style={{ color: T.success, flexShrink: 0 }} />;
  return <FileText size={14} style={{ color: T.textMuted, flexShrink: 0 }} />;
}

function fmtSize(n: number) {
  if (n < 1024) return `${n} B`;
  if (n < 1024 * 1024) return `${(n / 1024).toFixed(1)} KB`;
  return `${(n / 1024 / 1024).toFixed(1)} MB`;
}

export function FilesDrawer({ scriptsDir, onRun, onClose, width }: Props) {
  const fullScreen = width == null;
  const [cwd, setCwd] = useState('');
  const [entries, setEntries] = useState<Entry[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [editor, setEditor] = useState<{ path: string; content: string; isNew: boolean } | null>(null);
  const [saving, setSaving] = useState(false);
  const [menu, setMenu] = useState<{ x: number; y: number; entry: Entry } | null>(null);
  const uploadRef = useRef<HTMLInputElement | null>(null);

  const load = useCallback(async (path: string) => {
    setLoading(true); setError('');
    try {
      const res = await api.osTerminalListFiles(path);
      if (res?.type === 'dir') setEntries(res.entries ?? []);
      else setEntries([]);
    } catch (e: any) { setError(e?.message || 'error'); }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { load(cwd); }, [cwd, load]);
  useEffect(() => {
    const close = () => setMenu(null);
    if (menu) { window.addEventListener('scroll', close, true); }
    return () => { if (menu) window.removeEventListener('scroll', close, true); };
  }, [menu]);

  const navigate = (path: string) => { setCwd(path); setEditor(null); };
  const crumb = cwd ? cwd.split('/').filter(Boolean) : [];

  const openFile = async (entry: Entry) => {
    try {
      const res = await api.osTerminalReadFile(entry.path);
      if (res?.type === 'file') setEditor({ path: entry.path, content: res.content ?? '', isNew: false });
    } catch (e: any) { setError(e?.message || 'error'); }
  };

  const saveEditor = async () => {
    if (!editor) return;
    setSaving(true); setError('');
    try { await api.osTerminalWriteFile(editor.path, editor.content); setEditor(null); await load(cwd); }
    catch (e: any) { setError(e?.message || 'error'); }
    finally { setSaving(false); }
  };

  const newFile = () => {
    const name = prompt('Nombre del archivo (con extensión, ej. backup.sh):');
    if (!name) return;
    setEditor({ path: cwd ? `${cwd}/${name}` : name, content: '', isNew: true });
  };
  const newFolder = async () => {
    const name = prompt('Nombre de la carpeta:');
    if (!name) return;
    try { await api.osTerminalMkdir(cwd ? `${cwd}/${name}` : name); await load(cwd); }
    catch (e: any) { setError(e?.message || 'error'); }
  };

  const onUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files ?? []);
    if (!files.length) return;
    (async () => {
      for (const f of files) {
        const text = await f.text();
        try { await api.osTerminalWriteFile(cwd ? `${cwd}/${f.name}` : f.name, text); }
        catch (err: any) { setError(err?.message || 'upload error'); }
      }
      e.target.value = '';
      await load(cwd);
    })();
  };

  const remove = async (entry: Entry) => {
    if (!confirm(entry.isDir ? `¿Eliminar la carpeta "${entry.name}" y su contenido?` : `¿Eliminar "${entry.name}"?`)) return;
    try { await api.osTerminalDeleteFile(entry.path); await load(cwd); }
    catch (e: any) { setError(e?.message || 'error'); }
  };

  const runFile = (entry: Entry) => onRun(buildRunCommand(entry.path, scriptsDir) + '\n');

  const sorted = entries.slice().sort((a, b) => (a.isDir === b.isDir ? a.name.localeCompare(b.name) : a.isDir ? -1 : 1));

  return (
    <div
      className="shrink-0 flex flex-col min-h-0"
      style={fullScreen
        ? { position: 'absolute', inset: 0, width: '100%', zIndex: 50, background: T.panel, overflow: 'hidden' }
        : { width, background: T.panel, border: `1px solid ${T.borderLight}`, borderRadius: RADIUS, boxShadow: SHADOW_MD, overflow: 'hidden' }}
    >
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '8px 10px', borderBottom: `1px solid ${T.borderLight}`, background: T.toolbar }}>
        <FolderTree size={15} style={{ color: T.accent }} />
        <span style={{ fontSize: 12, fontWeight: 700, color: T.text }}>Archivos</span>
        <span style={{ fontSize: 10, color: T.textMuted, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', maxWidth: 120 }} title={scriptsDir}>{scriptsDir || '~/scripts'}</span>
        <div className="flex-1" />
        <GhostButton icon={<Home size={12} />} onClick={() => navigate('')} title="Raíz" />
        <GhostButton icon={<Plus size={12} />} label="Archivo" onClick={newFile} title="Nuevo archivo" />
        <GhostButton icon={<Folder size={12} />} label="Carpeta" onClick={newFolder} title="Nueva carpeta" />
        <GhostButton icon={<Upload size={12} />} label="Subir" onClick={() => uploadRef.current?.click()} title="Subir archivo(s)" />
        <GhostButton icon={<X size={12} />} onClick={onClose} title="Cerrar" />
        <input ref={uploadRef} type="file" multiple onChange={onUpload} className="hidden" />
      </div>

      {/* Breadcrumb */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 4, padding: '5px 10px', borderBottom: `1px solid ${T.borderLight}`, background: T.bg, overflowX: 'auto', whiteSpace: 'nowrap' }}>
        <button onClick={() => navigate('')} style={{ fontSize: 11, color: T.textSubtle, background: 'none', border: 'none', cursor: 'pointer', fontWeight: 600 }}>~/scripts</button>
        {crumb.map((part, i) => {
          const p = crumb.slice(0, i + 1).join('/');
          return (
            <span key={p} style={{ display: 'inline-flex', alignItems: 'center', gap: 3 }}>
              <ChevronRight size={11} style={{ color: T.textMuted }} />
              <button onClick={() => navigate(p)} style={{ fontSize: 11, color: T.textSubtle, background: 'none', border: 'none', cursor: 'pointer' }} onMouseEnter={(e) => { e.currentTarget.style.color = T.text; }} onMouseLeave={(e) => { e.currentTarget.style.color = T.textSubtle; }}>{part}</button>
            </span>
          );
        })}
      </div>

      {/* Editor */}
      {editor && (
        <div style={{ padding: 10, borderBottom: `1px solid ${T.borderLight}`, display: 'flex', flexDirection: 'column', gap: 6, maxHeight: '70%', background: T.bg }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <FileCode size={13} style={{ color: T.accent }} />
            <span style={{ fontSize: 11, fontWeight: 600, color: T.text, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', flex: 1 }}>{editor.isNew ? 'Nuevo' : 'Editar'}: {editor.path}</span>
            <Badge>{languageFromName(editor.path)}</Badge>
            <GhostButton icon={<X size={12} />} onClick={() => setEditor(null)} title="Cancelar" />
          </div>
          <CodeEditor
            path={editor.path}
            value={editor.content}
            onChange={(v) => setEditor({ ...editor, content: v })}
            onSave={saveEditor}
            height={fullScreen ? '60vh' : 300}
          />
          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginTop: 2 }}>
            <span style={{ fontSize: 10, color: T.textMuted }}>Ctrl+S guarda · ⌘S en Mac</span>
            <div className="flex-1" />
            <PrimaryButton onClick={saveEditor} disabled={saving}>{saving ? 'Guardando…' : 'Guardar'}</PrimaryButton>
          </div>
        </div>
      )}

      {error && <div style={{ padding: '4px 10px', fontSize: 11, color: T.danger, borderBottom: `1px solid ${T.borderLight}` }}>{error}</div>}

      {/* List */}
      <div className="flex-1 overflow-auto min-h-0" style={{ background: T.bg }}>
        {loading && <div style={{ padding: 10, fontSize: 11, color: T.textMuted }}>Cargando…</div>}
        {!loading && crumb.length > 0 && (
          <div
            onClick={() => navigate(crumb.slice(0, -1).join('/'))}
            style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '6px 10px', borderBottom: `1px solid ${T.borderLight}`, cursor: 'pointer', fontSize: 12, color: T.textSubtle }}
            onMouseEnter={(e) => { e.currentTarget.style.background = T.hover; }}
            onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; }}
          >
            <FolderOpen size={14} style={{ color: T.textMuted }} /> ..
          </div>
        )}
        {!loading && sorted.length === 0 && crumb.length === 0 && (
          <div style={{ padding: '16px 10px', fontSize: 11, color: T.textMuted, textAlign: 'center' }}>
            <Folder size={22} style={{ opacity: 0.4, marginBottom: 6 }} />
            <div>Carpeta vacía.</div>
            <div style={{ fontSize: 10, marginTop: 2 }}>Crea un archivo o <strong>Subir</strong> uno.</div>
          </div>
        )}
        {sorted.map((entry) => (
          <div
            key={entry.path}
            className="group"
            style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '6px 10px', borderBottom: `1px solid ${T.borderLight}`, cursor: 'pointer' }}
            onClick={() => entry.isDir ? navigate(entry.path) : openFile(entry)}
            onContextMenu={(e) => { e.preventDefault(); setMenu({ x: e.clientX, y: e.clientY, entry }); }}
            onMouseEnter={(e) => { e.currentTarget.style.background = T.hover; }}
            onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; }}
            title="Click = abrir · Click derecho = menú"
          >
            {fileIcon(entry)}
            <span style={{ fontSize: 12, color: T.text, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', flex: 1 }}>{entry.name}</span>
            {!entry.isDir && <span style={{ fontSize: 10, color: T.textMuted, fontVariantNumeric: 'tabular-nums' }}>{fmtSize(entry.size)}</span>}
            {!entry.isDir && (
              <span
                onClick={(e) => { e.stopPropagation(); runFile(entry); }}
                style={{ opacity: 0, transition: 'opacity 0.12s' }}
                className="group-hover:opacity-100"
                title="Ejecutar en pane activo"
              >
                <GhostButton icon={<Play size={12} />} />
              </span>
            )}
          </div>
        ))}
      </div>

      {menu && (
        <ContextMenu
          x={menu.x} y={menu.y}
          onClose={() => setMenu(null)}
          items={[
            { label: menu.entry.isDir ? 'Abrir carpeta' : 'Abrir', icon: menu.entry.isDir ? <FolderOpen size={13} /> : <FileText size={13} />, onClick: () => menu.entry.isDir ? navigate(menu.entry.path) : openFile(menu.entry) },
            ...(menu.entry.isDir ? [] : [{ label: 'Ejecutar en pane activo', icon: <Play size={13} />, onClick: () => runFile(menu.entry) }]),
            ...(menu.entry.isDir ? [] : [{ label: 'Editar', icon: <Pencil size={13} />, onClick: () => openFile(menu.entry) }]),
            { label: 'Eliminar', icon: <Trash2 size={13} />, danger: true, onClick: () => remove(menu.entry) },
          ]}
        />
      )}
    </div>
  );
}
